import type { Question } from '../types'

export const franceQuestions: Question[] = [
  // ── BORDEAUX ──────────────────────────────────────────────
  { id:'fr-bx-001', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Easy', question:'In which year was the famous Bordeaux wine classification created for the Paris Universal Exposition?', options:['1825','1855','1875','1900'], answer:1, explanation:'The 1855 Classification was commissioned by Napoleon III for the Paris Universal Exposition, ranking the top Médoc châteaux and Sauternes into five tiers.' },
  { id:'fr-bx-002', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Easy', question:'How many Premiers Crus (First Growths) are recognised in the 1855 Médoc Classification?', options:['Three','Four','Five','Six'], answer:2, explanation:'Five châteaux hold Premier Cru status: Mouton Rothschild (promoted 1973), Lafite Rothschild, Latour, Margaux, and Haut-Brion (the only Graves property).' },
  { id:'fr-bx-003', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Medium', question:'Which château was promoted from Second to First Growth in the 1855 Classification in 1973?', options:['Pétrus','Mouton Rothschild','Ausone','Cheval Blanc'], answer:1, explanation:'Château Mouton Rothschild was elevated to Premier Cru Classé in 1973 — the only change ever made to the 1855 red wine classification.' },
  { id:'fr-bx-004', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Medium', question:'Which is the only Graves property included in the 1855 Classification of Médoc wines?', options:['Domaine de Chevalier','Smith Haut Lafitte','Haut-Brion','Pichon Baron'], answer:2, explanation:'Château Haut-Brion (Pessac-Léognan/Graves) was included as an exception due to its exceptional reputation, making it the sole non-Médoc estate in the 1855 red classification.' },
  { id:'fr-bx-005', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Hard', question:'Which Saint-Émilion classification tier requires the highest level of testing and is revised approximately every ten years?', options:['Grand Cru','Grand Cru Classé','Premier Grand Cru Classé B','Premier Grand Cru Classé A'], answer:3, explanation:'Premier Grand Cru Classé A is the top tier of the Saint-Émilion classification, currently held by Ausone, Cheval Blanc, Angélus, and Pavie. The classification is revised roughly every decade, unlike the static 1855 Médoc classification.' },
  { id:'fr-bx-006', country:'France', region:'Bordeaux', topic:'Grape Varieties', difficulty:'Easy', question:'Which red grape variety dominates plantings on the Left Bank of Bordeaux?', options:['Merlot','Malbec','Cabernet Sauvignon','Cabernet Franc'], answer:2, explanation:'Cabernet Sauvignon thrives on the gravelly, well-drained soils of the Left Bank (Médoc, Pessac-Léognan), where it is the dominant variety in most blends.' },
  { id:'fr-bx-007', country:'France', region:'Bordeaux', topic:'Grape Varieties', difficulty:'Easy', question:'Which red grape variety dominates plantings on the Right Bank of Bordeaux?', options:['Cabernet Sauvignon','Petit Verdot','Merlot','Malbec'], answer:2, explanation:'Merlot ripens earlier and suits the clay-limestone soils of the Right Bank (Saint-Émilion, Pomerol), where it is the dominant blending component.' },
  { id:'fr-bx-008', country:'France', region:'Bordeaux', topic:'Grape Varieties', difficulty:'Medium', question:'Which white grape variety is the principal component of dry white Bordeaux and Pessac-Léognan whites?', options:['Muscadelle','Sémillon','Sauvignon Blanc','Viognier'], answer:2, explanation:'Sauvignon Blanc typically dominates the blend in dry white Bordeaux and Pessac-Léognan, providing freshness and aromatic lift, often blended with Sémillon.' },
  { id:'fr-bx-009', country:'France', region:'Bordeaux', topic:'Grape Varieties', difficulty:'Medium', question:'Which grape variety provides the backbone of Sauternes sweet wines, being particularly susceptible to noble rot?', options:['Sauvignon Blanc','Muscadelle','Sémillon','Chenin Blanc'], answer:2, explanation:'Sémillon has thin skin that allows Botrytis cinerea to penetrate easily, concentrating sugars and flavours. It forms the backbone of Sauternes, often making up 70–80% of the blend.' },
  { id:'fr-bx-010', country:'France', region:'Bordeaux', topic:'Grape Varieties', difficulty:'Hard', question:'Which minor Bordeaux red variety is valued for its contribution of dark colour, floral aromas, and high acid to blends, but is rarely bottled alone?', options:['Malbec','Carménère','Petit Verdot','Cabernet Franc'], answer:2, explanation:'Petit Verdot is a late-ripening variety that adds deep colour, spice, and structure to blends but is used in small quantities due to irregular ripening in Bordeaux\'s maritime climate.' },
  { id:'fr-bx-011', country:'France', region:'Bordeaux', topic:'Soils', difficulty:'Easy', question:'What type of soil characterises the best vineyards of the Haut-Médoc, aiding drainage and heat retention?', options:['Clay over limestone','Volcanic basalt','Deep gravel over clay subsoil','Sandy loam'], answer:2, explanation:'The Médoc\'s best estates sit on gravel ridges (croupes) over a clay subsoil and iron-rich hardpan (alios). The gravel drains rapidly, stresses vines, and retains daytime heat.' },
  { id:'fr-bx-012', country:'France', region:'Bordeaux', topic:'Soils', difficulty:'Medium', question:'What type of soil dominates the Right Bank appellations of Saint-Émilion and Pomerol?', options:['Deep river gravel','Clay and limestone','Volcanic tuff','Sandy loam over granite'], answer:1, explanation:'Clay-limestone soils predominate on the Right Bank. Clay retains moisture and suits Merlot\'s earlier budding, while limestone provides structure. Pomerol has areas of iron-rich clay (crasse de fer).' },
  { id:'fr-bx-013', country:'France', region:'Bordeaux', topic:'Climate', difficulty:'Easy', question:'Which ocean has the most direct moderating influence on Bordeaux\'s climate?', options:['Mediterranean Sea','Arctic Ocean','Atlantic Ocean','Indian Ocean'], answer:2, explanation:'The Atlantic Ocean gives Bordeaux a maritime climate — mild winters, warm summers, and sufficient rainfall. The Landes forest acts as a buffer between the coast and vineyards.' },
  { id:'fr-bx-014', country:'France', region:'Bordeaux', topic:'Climate', difficulty:'Medium', question:'Which two rivers converge near Bordeaux city, forming the Gironde Estuary that moderates the local climate?', options:['Garonne and Dordogne','Loire and Vienne','Rhône and Saône','Garonne and Loire'], answer:0, explanation:'The Garonne and Dordogne rivers meet at Bec d\'Ambès to form the Gironde estuary. Both rivers moderate temperature, reduce frost risk, and influence the microclimate of their respective banks.' },
  { id:'fr-bx-015', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Easy', question:'Which Bordeaux appellation is exclusively permitted to produce sweet white wines from botrytis-affected grapes?', options:['Graves','Pessac-Léognan','Sauternes','Pomerol'], answer:2, explanation:'Sauternes AOC produces exclusively sweet white wines from Sémillon, Sauvignon Blanc, and Muscadelle, all affected by Botrytis cinerea (noble rot).' },
  { id:'fr-bx-016', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Easy', question:'Which Médoc appellation is home to châteaux Lafite Rothschild, Latour, and Mouton Rothschild?', options:['Margaux','Saint-Julien','Pauillac','Saint-Estèphe'], answer:2, explanation:'Pauillac contains three of the five Premiers Crus: Mouton Rothschild, Latour, and Lafite Rothschild. It is widely considered the greatest Médoc commune for Cabernet Sauvignon.' },
  { id:'fr-bx-017', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Medium', question:'Which appellation covers both the northern Médoc (around Pauillac, Saint-Julien) as an overarching regional label?', options:['Bordeaux AOC','Haut-Médoc AOC','Médoc AOC','Listrac-Médoc AOC'], answer:1, explanation:'Haut-Médoc is the broader AOC covering the southern and most prestigious part of the Médoc peninsula, encompassing the communal appellations of Margaux, Pauillac, Saint-Julien, and Saint-Estèphe.' },
  { id:'fr-bx-018', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Medium', question:'Château Pétrus, one of Bordeaux\'s most expensive wines, is located in which appellation?', options:['Saint-Émilion','Fronsac','Pomerol','Lalande de Pomerol'], answer:2, explanation:'Pétrus is located in Pomerol, a small Right Bank appellation with no official classification. It sits on a unique clay plateau rich in iron (crasse de fer), producing almost pure Merlot.' },
  { id:'fr-bx-019', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Hard', question:'Which appellation, encircled by Pessac-Léognan, produces both top red and white wines with a separate Crus Classés de Graves classification?', options:['Graves Supérieures','Pessac-Léognan','Cerons','Haut-Médoc'], answer:1, explanation:'Pessac-Léognan was created in 1987 as a separate AOC within Graves, home to the classified Crus Classés de Graves including Haut-Brion, Domaine de Chevalier, and Smith Haut Lafitte, producing both red and white wines.' },
  { id:'fr-bx-020', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Easy', question:'What winemaking process do nearly all Bordeaux red wines undergo to soften acidity after primary fermentation?', options:['Carbonic maceration','Extended cold soak','Malolactic fermentation','Flash détente'], answer:2, explanation:'Malolactic fermentation (MLF) converts sharp malic acid to softer lactic acid, reducing acidity and increasing complexity. It is standard practice for all serious Bordeaux red wines.' },
  { id:'fr-bx-021', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Medium', question:'Château d\'Yquem is the sole Premier Cru Supérieur in Sauternes. Approximately how long can each vine produce only one glass of wine per harvest?', options:['The vine produces one bottle per harvest','One glass per vine per harvest','The vine produces one barrel per hectare','Each vine produces ten litres'], answer:1, explanation:'The extreme selectivity at Yquem — picking individual botrytised berries over multiple passes — results in yields so low that each vine produces roughly one glass of wine. This contributes to the wine\'s exceptional price.' },
  { id:'fr-bx-022', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Medium', question:'What is the French term for the practice of buying Bordeaux wines as "futures" before bottling?', options:['Négociant','En primeur','Courtier','Place de Bordeaux'], answer:1, explanation:'En primeur (also called "futures") allows buyers to purchase wines about six months after harvest, before bottling. The wine is delivered 18–24 months later. It helps châteaux with cash flow and gives buyers early access.' },
  { id:'fr-bx-023', country:'France', region:'Bordeaux', topic:'Business', difficulty:'Medium', question:'What is the name of the Bordeaux trading system through which négociants buy wine from châteaux via courtiers?', options:['Courtage system','Place de Bordeaux','En primeur network','Syndicat des Grands Crus'], answer:1, explanation:'The Place de Bordeaux is the three-tier trading system (château → courtier/broker → négociant/merchant) through which most Bordeaux wines are distributed globally, enabling châteaux to reach world markets without direct sales forces.' },
  { id:'fr-bx-024', country:'France', region:'Bordeaux', topic:'Styles', difficulty:'Easy', question:'What is the principal style of wine produced in the Sauternes appellation?', options:['Dry white','Dry red','Botrytis-affected sweet white','Fortified wine'], answer:2, explanation:'Sauternes produces luscious sweet white wines made from grapes affected by Botrytis cinerea (noble rot), which concentrates sugars, acids, and glycerol, giving the wines their characteristic richness and complexity.' },
  { id:'fr-bx-025', country:'France', region:'Bordeaux', topic:'Wine Law', difficulty:'Hard', question:'Under Bordeaux AOC rules, which statement about rosé wine production in the appellation is correct?', options:['Rosé may be made by blending red and white wines','Rosé must use only Cabernet Sauvignon','Rosé Bordeaux must be made by the saignée or direct pressing method only','Rosé production is prohibited in Bordeaux'], answer:2, explanation:'In Bordeaux AOC, rosé must be made by the saignée method (bleeding off juice after brief skin contact) or by direct pressing — blending red and white wines to make rosé is not permitted for still wines under EU and French law.' },
  { id:'fr-bx-026', country:'France', region:'Bordeaux', topic:'Topography', difficulty:'Medium', question:'What term describes the small gravel ridges on which the best Médoc châteaux are typically located?', options:['Croupes','Galets','Alios','Coteaux'], answer:0, explanation:'Croupes are low gravel ridges or hillocks that provide the key drainage and heat retention for the best Médoc vineyards. The finest châteaux (Lafite, Latour, Margaux) occupy distinct croupes.' },
  { id:'fr-bx-027', country:'France', region:'Bordeaux', topic:'Grape Growing', difficulty:'Medium', question:'Which Bordeaux wine disease, caused by the oomycete Plasmopara viticola, was inadvertently introduced from North America in the 1870s?', options:['Powdery mildew (oïdium)','Phylloxera','Downy mildew (mildiou)','Black rot'], answer:2, explanation:'Downy mildew (mildiou) arrived in Bordeaux from North America in the 1870s along with phylloxera, devastating vineyards. Bordeaux Mixture (copper sulphate and lime) was developed here as a treatment.' },
  { id:'fr-bx-028', country:'France', region:'Bordeaux', topic:'Grape Growing', difficulty:'Easy', question:'What viticultural practice, common in Bordeaux, involves removing excess green grape bunches early in the season to concentrate flavour in the remaining fruit?', options:['Bleeding (saignée)','Green harvest (vendange verte)','Gobelet pruning','Effeuillage'], answer:1, explanation:'Green harvest (vendange verte) involves cutting off unripe bunches in summer to reduce yields, concentrating flavour, sugars, and phenolics in the remaining clusters. It is particularly important in high-yielding years.' },
  { id:'fr-bx-029', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Hard', question:'The Cru Bourgeois classification of the Haut-Médoc is revised how frequently, unlike the static 1855 classification?', options:['Every year','Every five years','Every ten years','It is also static'], answer:1, explanation:'The Cru Bourgeois classification is reviewed every five years (unlike the 1855 which has only changed once). The current system was established after a 2003 classification was annulled by courts, with a new system launched in 2010.' },
  { id:'fr-bx-030', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Hard', question:'What is the purpose of the "assemblage" stage in Bordeaux winemaking?', options:['Pumping over to extract colour','The final blending of different grape varieties and parcels','Racking wine off its lees','Fining the wine before bottling'], answer:1, explanation:'Assemblage is the critical blending stage where the winemaker combines wines from different varieties, parcels, and sometimes vintages to create the final blend. It determines the proportion of Cabernet Sauvignon, Merlot, Cabernet Franc, and other varieties in the final wine.' },
  { id:'fr-bx-031', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Easy', question:'Château Margaux is the eponymous estate of which communal Médoc appellation known for elegance and perfumed wines?', options:['Saint-Estèphe','Saint-Julien','Margaux','Listrac-Médoc'], answer:2, explanation:'Margaux AOC is the southernmost communal appellation of the Haut-Médoc. It is known for perfumed, elegant Cabernet Sauvignon-dominant wines. Château Margaux, a Premier Cru, is the appellation\'s most famous estate.' },
  { id:'fr-bx-032', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Medium', question:'Which Right Bank appellation borders Pomerol to the north and is considered a less expensive alternative for similar Merlot-dominant wines?', options:['Fronsac','Lalande de Pomerol','Canon-Fronsac','Saint-Georges-Saint-Émilion'], answer:1, explanation:'Lalande de Pomerol is the satellite appellation directly north of Pomerol. It produces Merlot-dominant wines at lower prices, sharing similar clay soils and can offer excellent value.' },
  { id:'fr-bx-033', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Medium', question:'What is the typical barrel size used for ageing premium Bordeaux red wines?', options:['228-litre piece (Burgundy barrel)','500-litre demi-muid','225-litre barrique bordelaise','600-litre puncheon'], answer:2, explanation:'The 225-litre barrique bordelaise is the standard barrel for ageing premium Bordeaux red wines. This smaller size imparts more oak flavour and allows gradual micro-oxygenation over the typical 18–24 months of ageing.' },
  { id:'fr-bx-034', country:'France', region:'Bordeaux', topic:'Styles', difficulty:'Medium', question:'Which style of white wine is exclusively produced in the Graves Supérieures and Cérons appellations?', options:['Dry unoaked white','Sweet to medium-sweet white wine','Sparkling white wine','Fortified white wine'], answer:1, explanation:'Graves Supérieures and Cérons produce sweet to semi-sweet white wines from botrytis-affected and late-harvest Sémillon, Sauvignon Blanc, and Muscadelle, distinct from the dry whites of Pessac-Léognan and Graves.' },
  { id:'fr-bx-035', country:'France', region:'Bordeaux', topic:'Business', difficulty:'Hard', question:'Which large luxury goods group owns Châteaux Cheval Blanc and Yquem, among others, reflecting the financialisation of Bordeaux?', options:['LVMH','Kering','Pernod Ricard','AXA Millésimes'], answer:0, explanation:'LVMH (Moët Hennessy Louis Vuitton) owns Château d\'Yquem and Château Cheval Blanc. AXA Millésimes owns Pichon Baron, Petit Village, Suduiraut, and others. This illustrates Bordeaux\'s appeal to large investment groups.' },
  { id:'fr-bx-036', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Easy', question:'Barsac is a commune that can use its own appellation name or sell wines under which broader sweet wine appellation?', options:['Graves Supérieures','Cérons','Sauternes','Loupiac'], answer:2, explanation:'Barsac wines can be labelled either as "Barsac AOC" or "Sauternes AOC". The production methods and permitted varieties are identical, but many Barsac producers choose to use the Sauternes name for marketing.' },
  { id:'fr-bx-037', country:'France', region:'Bordeaux', topic:'Soils', difficulty:'Hard', question:'What is "alios" in the context of Bordeaux terroir?', options:['A type of grey clay found in Pomerol','An iron-rich hardpan layer beneath Médoc gravel that impedes drainage','The chalky marl beneath Sauternes vineyards','A term for dark alluvial soil in the Graves'], answer:1, explanation:'Alios is the iron-rich hardpan or cemented subsoil layer beneath the gravel in the Médoc. It prevents deep root penetration and forces vines to stress — an important terroir factor in some areas, though it can also impede drainage.' },
  { id:'fr-bx-038', country:'France', region:'Bordeaux', topic:'Climate', difficulty:'Medium', question:'Which weather phenomenon, occurring during the growing season in Bordeaux, allows fungal diseases to thrive and is associated with the maritime climate?', options:['Mistral winds','High humidity and rainfall during vintage','Very high temperatures in July','Spring frost'], answer:1, explanation:'Bordeaux\'s maritime climate brings humid conditions, especially during the crucial September–October harvest period, creating risk of grey rot (Botrytis cinerea in its destructive form) and other fungal diseases.' },
  { id:'fr-bx-039', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Medium', question:'Which two Médoc communal appellations do NOT have any classified growths from the 1855 classification?', options:['Listrac-Médoc and Moulis-en-Médoc','Pauillac and Margaux','Saint-Julien and Saint-Estèphe','Margaux and Listrac-Médoc'], answer:0, explanation:'Listrac-Médoc and Moulis-en-Médoc are the only two communal Haut-Médoc appellations without any 1855 Classified Growth châteaux, though they do have Cru Bourgeois classified estates.' },
  { id:'fr-bx-040', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Medium', question:'What technique, used in some Right Bank wineries, involves running a pump to spray fermenting juice over the cap of grape skins to extract colour and tannin?', options:['Délestage','Pigeage','Remontage','Bâtonnage'], answer:2, explanation:'Remontage (pumping over) involves pumping fermenting juice from the bottom of the tank up and over the floating cap of grape skins. It extracts colour, tannin, and flavour. Pigeage (punch-down) and délestage (rack and return) are alternative extraction methods.' },
  // ── BURGUNDY ──────────────────────────────────────────────
  { id:'fr-bu-001', country:'France', region:'Burgundy', topic:'Classification', difficulty:'Easy', question:'What is the top tier of the Burgundy quality classification system?', options:['Premier Cru','Village','Grand Cru','Régionale'], answer:2, explanation:'Grand Cru is the highest tier, representing specific vineyard sites of exceptional quality. There are 33 Grand Cru AOCs in Burgundy, all in the Côte d\'Or (plus Chablis and Musigny in Chambolle).' },
  { id:'fr-bu-002', country:'France', region:'Burgundy', topic:'Classification', difficulty:'Medium', question:'Approximately how many Premier Cru vineyard sites exist within the Côte d\'Or?', options:['Fewer than 50','Around 100','Around 600','Over 1,000'], answer:2, explanation:'There are approximately 600 Premier Cru climat (vineyard sites) in the Côte d\'Or alone, across villages including Gevrey-Chambertin, Chambolle-Musigny, Beaune, and Meursault.' },
  { id:'fr-bu-003', country:'France', region:'Burgundy', topic:'Classification', difficulty:'Hard', question:'What is a "climat" in Burgundy viticulture?', options:['A specific microclimate pattern across the whole Côte d\'Or','A legally delimited individual vineyard plot with its own name and AOC','The annual weather conditions affecting vintage quality','A co-operative wine producer in Burgundy'], answer:1, explanation:'A climat is a legally defined, named vineyard plot unique to Burgundy. Each climat has its own AOC status (Grand Cru, Premier Cru, or Village). The Burgundy climat system was inscribed on the UNESCO World Heritage List in 2015.' },
  { id:'fr-bu-004', country:'France', region:'Burgundy', topic:'Grape Varieties', difficulty:'Easy', question:'Which red grape variety is exclusively used for red wines in the Côte d\'Or?', options:['Gamay','Aligoté','Cabernet Sauvignon','Pinot Noir'], answer:3, explanation:'Pinot Noir is the sole permitted red grape variety for Village, Premier Cru, and Grand Cru AOC wines in the Côte d\'Or. Gamay is used in Bourgogne Passe-Tout-Grains (mixed with Pinot Noir) and Beaujolais.' },
  { id:'fr-bu-005', country:'France', region:'Burgundy', topic:'Grape Varieties', difficulty:'Easy', question:'Which white grape variety dominates Burgundy\'s white wine production, including all Chablis and Côte de Beaune whites?', options:['Viognier','Chardonnay','Aligoté','Pinot Gris'], answer:1, explanation:'Chardonnay produces all the major white Burgundies — Chablis, Meursault, Puligny-Montrachet, Chassagne-Montrachet, and the Côte Chalonnaise whites. Aligoté is used only in Bourgogne Aligoté AOC.' },
  { id:'fr-bu-006', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Which Burgundy village is home to the Grand Cru vineyard La Tâche and the domaine Romanée-Conti?', options:['Gevrey-Chambertin','Chambolle-Musigny','Flagey-Échézeaux','Vosne-Romanée'], answer:3, explanation:'Vosne-Romanée contains some of Burgundy\'s most prized Grand Crus: Romanée-Conti, La Tâche, Richebourg, La Romanée, Romanée-Saint-Vivant, and La Grande Rue — all owned or partly owned by Domaine de la Romanée-Conti (DRC).' },
  { id:'fr-bu-007', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Which village in the Côte de Beaune is most famous for its Grand Cru white wines, including Le Montrachet shared with Chassagne?', options:['Meursault','Pernand-Vergelesses','Puligny-Montrachet','Auxey-Duresses'], answer:2, explanation:'Puligny-Montrachet is home to Grand Cru white vineyards including Le Montrachet (shared with Chassagne), Bâtard-Montrachet, Bienvenues-Bâtard-Montrachet, and Chevalier-Montrachet. Meursault is Premier Cru only (no Grand Cru white).' },
  { id:'fr-bu-008', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Easy', question:'In which sub-region of Burgundy is the Grand Cru appellation Chambertin located?', options:['Côte de Beaune','Côte Chalonnaise','Côte de Nuits','Mâconnais'], answer:2, explanation:'Chambertin is a Grand Cru located in Gevrey-Chambertin village in the Côte de Nuits. Napoleon was famously fond of Chambertin. Nine Grand Crus include "Chambertin" in their name.' },
  { id:'fr-bu-009', country:'France', region:'Burgundy', topic:'Soils', difficulty:'Medium', question:'What type of soil geology, containing fossilised oyster shells, characterises the core of the Chablis Grand Cru vineyard area?', options:['Portlandian limestone','Kimmeridgian marl and limestone','Barremian clay','Miocene sand'], answer:1, explanation:'Kimmeridgian marl and limestone, formed from ancient seabed with oyster fossils (Exogyra virgula), is the characteristic soil of Chablis Grand Cru and Premier Cru vineyards, contributing to the wines\' mineral, flinty character.' },
  { id:'fr-bu-010', country:'France', region:'Burgundy', topic:'Soils', difficulty:'Medium', question:'Which type of limestone soil, often with red-brown iron-rich clay, is found on the mid-slopes of the Côte de Nuits and is considered optimal for Pinot Noir?', options:['Jurassic limestone and marl (calcaire)','Granite and gneiss','Alluvial silt and gravel','Chalk'], answer:0, explanation:'The Côte de Nuits mid-slopes feature Jurassic limestone and marl (often called calcaire or comblanchien limestone), sometimes mixed with iron-rich clay. This complex geology is a key factor in the diversity of Pinot Noir styles across different villages.' },
  { id:'fr-bu-011', country:'France', region:'Burgundy', topic:'Winemaking', difficulty:'Medium', question:'What is "bâtonnage" in white Burgundy production?', options:['Pressing whole clusters to avoid skin contact','Stirring the wine\'s lees during ageing to add richness','Racking the wine off its gross lees after fermentation','Blending different vineyard parcels after ageing'], answer:1, explanation:'Bâtonnage (lees stirring) involves periodically stirring the fine lees (dead yeast cells) back into the wine during barrel ageing. It adds weight, texture, and autolytic complexity (bread/yeast notes) to white Burgundy.' },
  { id:'fr-bu-012', country:'France', region:'Burgundy', topic:'Winemaking', difficulty:'Hard', question:'In red Burgundy production, what does "vendange entière" (whole-cluster fermentation) involve, and what does it contribute?', options:['Crushing and destemming all grapes before fermentation to maximise extraction','Fermenting intact grape bunches including stems, adding structure and spice','Using carbonic maceration for Pinot Noir to soften tannins','Fermenting only free-run juice without pressing'], answer:1, explanation:'Vendange entière means fermenting whole grape bunches including stalks. The stems can contribute additional tannin, earthy notes, and structure. Its use is hotly debated — traditionalists (e.g. Leroy) favour it; others partially or fully destem.' },
  { id:'fr-bu-013', country:'France', region:'Burgundy', topic:'Business', difficulty:'Medium', question:'What is the role of a "négociant-éleveur" in Burgundy\'s wine trade?', options:['A grower who owns vineyards and makes wine from their own grapes only','A merchant who buys grapes or wine, then ages and bottles it under their own label','A cooperative that pools grapes from multiple growers','A government-appointed wine inspector'], answer:1, explanation:'A négociant-éleveur buys grapes, must, or wine from multiple growers, then ages and bottles under their own label. Famous Burgundy négociants include Louis Jadot, Joseph Drouhin, Louis Latour, and Bouchard Père et Fils.' },
  { id:'fr-bu-014', country:'France', region:'Burgundy', topic:'Business', difficulty:'Medium', question:'What is a "domaine" in Burgundy, and how does it differ from a négociant?', options:['A domaine buys grapes from many growers; a négociant grows its own grapes','A domaine grows its own grapes and makes wine from them; a négociant buys grapes or wine','A domaine is a government wine board; a négociant is a private grower','There is no meaningful difference between the two terms'], answer:1, explanation:'A domaine is an estate that grows its own grapes (from owned or leased vineyards) and makes wine entirely from those grapes. A négociant buys grapes, must, or finished wine from other growers. Some Burgundy estates (e.g. Faiveley, Drouhin) operate as both.' },
  { id:'fr-bu-015', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Hard', question:'Which Burgundy village gives its name to a communal AOC that unusually allows both red and white wines to include the term "Grand Cru" in their appellation — Corton for red and Corton-Charlemagne for white?', options:['Beaune','Aloxe-Corton','Nuits-Saint-Georges','Pommard'], answer:1, explanation:'Aloxe-Corton (along with parts of Pernand-Vergelesses and Ladoix-Serrigny) contains both Corton Grand Cru (red, from Pinot Noir) and Corton-Charlemagne Grand Cru (white, from Chardonnay). Corton is the only red Grand Cru in the Côte de Beaune.' },
  { id:'fr-bu-016', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Which Côte Chalonnaise village is known exclusively for Aligoté production, with its own AOC — Bouzeron AOC?', options:['Mercurey','Rully','Bouzeron','Givry'], answer:2, explanation:'Bouzeron AOC is unique in Burgundy for producing exclusively Aligoté wine. The village is home to Domaine A. & P. de Villaine (owned by the co-director of DRC), which championed quality Aligoté production.' },
  { id:'fr-bu-017', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Easy', question:'Pouilly-Fuissé is the most prestigious white wine AOC in which Burgundy sub-region?', options:['Côte de Beaune','Côte Chalonnaise','Chablis','Mâconnais'], answer:3, explanation:'Pouilly-Fuissé is the top white wine appellation of the Mâconnais, producing Chardonnay-based wines. Premier Cru status within Pouilly-Fuissé was officially introduced in 2020, the first new Burgundy PCs in decades.' },
  { id:'fr-bu-018', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Easy', question:'Chablis Grand Cru has seven named vineyards. Which of the following is NOT one of them?', options:['Les Clos','Vaudésir','Blanchot','Chambolle'], answer:3, explanation:'The seven Chablis Grand Cru vineyards are: Blanchot, Bougros, Les Clos, Grenouilles, Preuses, Valmur, and Vaudésir. Chambolle is a Côte de Nuits village, not a Chablis Grand Cru.' },
  { id:'fr-bu-019', country:'France', region:'Burgundy', topic:'Styles', difficulty:'Medium', question:'How does a typical Gevrey-Chambertin red compare stylistically to a Chambolle-Musigny red from the same producer?', options:['Gevrey is typically lighter and more floral; Chambolle is more structured and tannic','Gevrey is typically fuller-bodied and more structured; Chambolle is more delicate and floral','Both appellations produce identical wines due to the same soil type','Gevrey produces white wine; Chambolle produces red'], answer:1, explanation:'Gevrey-Chambertin reds are typically richer, more tannic, and structured (due to heavier soils). Chambolle-Musigny reds are renowned for their delicacy, finesse, and floral perfume (violets, roses), partly due to thin, well-draining soils.' },
  { id:'fr-bu-020', country:'France', region:'Burgundy', topic:'Climate', difficulty:'Easy', question:'What type of climate does Burgundy experience, with cold winters and warm, sometimes hot summers?', options:['Maritime','Mediterranean','Continental','Semi-arid'], answer:2, explanation:'Burgundy has a continental climate with cold winters, warm summers, and the risk of spring frost. The lack of a large water body means less temperature moderation than in Bordeaux, making vintage variation more pronounced.' },
  { id:'fr-bu-021', country:'France', region:'Burgundy', topic:'Grape Varieties', difficulty:'Medium', question:'Bourgogne Aligoté AOC is produced from which Burgundy white grape variety?', options:['Chardonnay','Pinot Blanc','Pinot Gris','Aligoté'], answer:3, explanation:'Aligoté is an ancient Burgundy white variety used for Bourgogne Aligoté AOC. It is typically lighter and higher in acidity than Chardonnay. Aligoté is a key ingredient in Kir cocktail (Aligoté with blackcurrant liqueur).' },
  { id:'fr-bu-022', country:'France', region:'Burgundy', topic:'Wine Law', difficulty:'Hard', question:'What is a "monopole" in Burgundy, and which famous Grand Cru is the most cited example?', options:['A vineyard split between many owners with no single dominant producer','A Grand Cru entirely owned by a single estate, not shared with other producers','A négociant who has exclusive contracts with multiple growers','A cooperative appellation with guaranteed minimum quality'], answer:1, explanation:'A monopole is a Grand Cru (or Premier Cru) entirely owned by a single producer. Romanée-Conti Grand Cru is the most famous, owned 100% by Domaine de la Romanée-Conti. La Tâche, Richebourg, and others at DRC are also largely or entirely monopoles.' },
  { id:'fr-bu-023', country:'France', region:'Burgundy', topic:'Winemaking', difficulty:'Medium', question:'What percentage of new oak is typically used for Grand Cru red Burgundy compared to Village level wines?', options:['Grand Cru: 10–20% new oak; Village: 100% new oak','Grand Cru: 80–100% new oak; Village: 10–30% new oak','Grand Cru: 50% new oak; Village: 50% new oak','New oak is never used in Burgundy'], answer:1, explanation:'Grand Cru red Burgundies often use a high proportion of new French oak (80–100% in some cases), while Village wines use far less (10–30%) to avoid overwhelming Pinot Noir\'s delicate fruit. The exact percentage is a key stylistic decision for each producer.' },
  { id:'fr-bu-024', country:'France', region:'Burgundy', topic:'Soils', difficulty:'Hard', question:'Which Burgundy village is geologically unusual for having its Grand Cru vineyards on a different geological formation (Triassic limestone and iron-rich clay) compared to most Côte de Nuits Grand Crus?', options:['Gevrey-Chambertin','Morey-Saint-Denis','Nuits-Saint-Georges','Vosne-Romanée'], answer:2, explanation:'Nuits-Saint-Georges has no Grand Cru but its Premier Crus (especially on the southern side bordering Vosne) sit on different geological strata. However, geologically, the complexity of Burgundy soils varies by slope position — this is a genuinely complex topic that winemakers and geologists debate.' },
  { id:'fr-bu-025', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Which Côte de Beaune village is famous for its red wines (Premier Crus such as Les Rugiens) rather than whites?', options:['Meursault','Puligny-Montrachet','Pommard','Chassagne-Montrachet'], answer:2, explanation:'Pommard is known for structured, tannic red Burgundy from Premier Crus such as Les Rugiens and Les Épenots. Unlike its neighbours Meursault and Puligny-Montrachet, Pommard produces almost exclusively red wine.' },
  { id:'fr-bu-026', country:'France', region:'Burgundy', topic:'Business', difficulty:'Medium', question:'Which Burgundy region — despite having no Grand Cru — is the engine of Burgundy\'s volume production and contains the Hospices de Beaune charity auction?', options:['Gevrey-Chambertin','Beaune','Nuits-Saint-Georges','Meursault'], answer:1, explanation:'Beaune is the commercial capital of Burgundy. The annual Hospices de Beaune wine auction in November sets benchmark prices for Burgundy wines. Beaune itself has no Grand Cru, only Premier Crus.' },
  { id:'fr-bu-027', country:'France', region:'Burgundy', topic:'Grape Varieties', difficulty:'Hard', question:'Bourgogne Passe-Tout-Grains AOC blends Gamay and Pinot Noir. What is the minimum percentage of Pinot Noir required?', options:['10%','25%','33%','50%'], answer:2, explanation:'Bourgogne Passe-Tout-Grains AOC must contain at least one-third Pinot Noir, with the remainder being Gamay (and up to 15% other Burgundy varieties). It is a simple quaffing red from Burgundy.' },
  { id:'fr-bu-028', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Which appellation in the Côte Chalonnaise is known primarily for Chardonnay-based sparkling wine production (Crémant de Bourgogne) as well as still whites?', options:['Montagny','Mercurey','Rully','Givry'], answer:2, explanation:'Rully AOC in the Côte Chalonnaise produces both still whites (Chardonnay) and is a major source of Crémant de Bourgogne (sparkling wine made by the traditional method). It also produces some red from Pinot Noir.' },
  { id:'fr-bu-029', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Which Mâconnais appellation, alongside Pouilly-Fuissé, has been recognised as producing the region\'s finest Chardonnay?', options:['Mâcon-Villages','Crémant de Bourgogne','Saint-Véran','Viré-Clessé'], answer:3, explanation:'Viré-Clessé AOC (elevated from Mâcon-Villages in 1999) produces high-quality Chardonnay from limestone soils around the villages of Viré and Clessé. Saint-Véran is also important. Both neighbour Pouilly-Fuissé.' },
  { id:'fr-bu-030', country:'France', region:'Burgundy', topic:'Topography', difficulty:'Medium', question:'Where on the Côte d\'Or slope are Grand Cru vineyards typically located, relative to Village and Premier Cru sites?', options:['At the very top of the slope, above the Premier Crus','In the valley bottom where soils are deepest','On the mid-slope, often on a specific geological band','On flat ground at the base of the slope'], answer:2, explanation:'Grand Cru vineyards occupy the most favourable mid-slope positions on the Côte d\'Or, where thin, well-draining soils overlay bedrock. Premier Crus are typically nearby. Village appellations occupy lower slopes or flatter ground with deeper, more fertile soils.' },
  { id:'fr-bu-031', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Hard', question:'Which village in the Côte de Nuits is unusual for being split between two communes — one portion in Vosne-Romanée and one in Nuits-Saint-Georges — and contains the Grand Cru vineyard Échézeaux?', options:['Chambolle-Musigny','Morey-Saint-Denis','Flagey-Échézeaux','Vougeot'], answer:2, explanation:'Flagey-Échézeaux is a commune that administratively falls partly in Vosne-Romanée. It contains two Grand Crus: Échézeaux and Grands-Échézeaux. Its Village and regional wines are sold under the Vosne-Romanée label.' },
  { id:'fr-bu-032', country:'France', region:'Burgundy', topic:'Winemaking', difficulty:'Easy', question:'Chablis is traditionally described as unoaked or only lightly oaked, retaining a distinctive character. Which Chablis producer famously advocates ageing in large old oak casks (foudres)?', options:['Raveneau','Louis Michel','William Fèvre','René et Vincent Dauvissat'], answer:2, explanation:'William Fèvre (now owned by Joseph Henriot) traditionally uses stainless steel like most Chablis producers, but Domaine Raveneau and some others DO use some old oak. The classic debate is between steel (Dauvissat, Michel) and judicious oak (Drouhin-Vaudon, Fevre). Louis Jadot is also a significant négociant in Chablis.' },
  { id:'fr-bu-033', country:'France', region:'Burgundy', topic:'Climate', difficulty:'Hard', question:'Which Burgundy sub-region is most vulnerable to spring frost due to its flat valley floor and proximity to cold rivers, requiring expensive frost protection methods?', options:['Côte de Nuits','Chablis','Mâconnais','Côte de Beaune'], answer:1, explanation:'Chablis is highly vulnerable to spring frost because of its northerly location, flat vineyard areas, and proximity to the Serein River. Frost protection methods including smudge pots (chaufferettes), wind machines, and overhead sprinklers (aspersion) are widely used.' },
  { id:'fr-bu-034', country:'France', region:'Burgundy', topic:'Styles', difficulty:'Medium', question:'How do the white wines of Meursault typically differ from those of Puligny-Montrachet?', options:['Meursault is typically more mineral and austere; Puligny is richer and more oaky','Meursault is typically richer, more buttery and hazelnut-driven; Puligny is finer, more mineral and precise','Both villages produce identical styles from the same soils','Meursault produces only red wine; Puligny makes only white'], answer:1, explanation:'Meursault whites (from deeper, less stony soils) are typically broader, richer, with butter and hazelnut notes, and often oak-influenced. Puligny-Montrachet (rockier, better-drained soils near Le Montrachet) tends toward greater precision, minerality, and citrus freshness.' },
  { id:'fr-bu-035', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'Clos de Vougeot Grand Cru is historically significant in Burgundy. Approximately how many different owners does this single Grand Cru vineyard have?', options:['One owner (a monopole)','Around 5 owners','Over 80 owners','Over 300 owners'], answer:2, explanation:'Clos de Vougeot Grand Cru (about 50 hectares) is famously divided among over 80 different owners, reflecting the Burgundy system of inheritance subdivision. This is why the same Grand Cru can produce wildly different quality wines.' },
  { id:'fr-bu-036', country:'France', region:'Burgundy', topic:'Grape Varieties', difficulty:'Medium', question:'What is the Burgundy regional wine category that allows Pinot Noir, Chardonnay, Aligoté, and Gamay from across the region?', options:['Bourgogne Grand Ordinaire','Crémant de Bourgogne','Bourgogne AOC (Régionale)','Coteaux Bourguignons'], answer:2, explanation:'Bourgogne AOC is the broad regional appellation covering the whole of Burgundy. Wines can be red (Pinot Noir), white (Chardonnay or Aligoté), or rosé. Quality varies enormously, from négociant blends to serious estate wines from declassified Grand Cru parcels.' },
  { id:'fr-bu-037', country:'France', region:'Burgundy', topic:'Winemaking', difficulty:'Medium', question:'What process does Crémant de Bourgogne use to produce its bubbles?', options:['CO2 injection','Charmat/tank method','Traditional method (méthode traditionnelle)','Ancestral method (pétillant naturel)'], answer:2, explanation:'Crémant de Bourgogne is made by the traditional method (secondary fermentation in bottle, riddling, and disgorgement). It must have a minimum of 9 months\' lees ageing. The main grapes are Chardonnay, Pinot Noir, and Aligoté.' },
  { id:'fr-bu-038', country:'France', region:'Burgundy', topic:'Business', difficulty:'Hard', question:'What is a "courtier" in Burgundy\'s wine trade and how do they differ from a négociant?', options:['A courtier is a broker who facilitates sales between growers and négociants without taking ownership of the wine','A courtier is a wine producer who sells directly to consumers','A courtier is a government-certified quality inspector','A courtier owns vineyards and sells wine under their own label'], answer:0, explanation:'A courtier (broker) facilitates transactions between growers/cooperatives and négociants, taking a commission without owning the wine. They have deep knowledge of available stocks and prices. This three-tier system (grower → courtier → négociant → consumer) is characteristic of both Burgundy and Bordeaux.' },
  { id:'fr-bu-039', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Hard', question:'Which AOC in the Côte de Nuits produces both red and white wines under the same village name, but is better known for its reds, with Les Saint-Georges considered Premier Cru of exceptional quality?', options:['Gevrey-Chambertin','Chambolle-Musigny','Morey-Saint-Denis','Nuits-Saint-Georges'], answer:3, explanation:'Nuits-Saint-Georges produces red wines from Pinot Noir and small amounts of white (from Chardonnay). Les Saint-Georges Premier Cru has long been considered de facto Grand Cru quality and was the subject of an application to upgrade its status.' },
  { id:'fr-bu-040', country:'France', region:'Burgundy', topic:'Grape Varieties', difficulty:'Hard', question:'Pinot Blanc and Pinot Gris are technically permitted in some Burgundy AOCs. Which statement about them is correct?', options:['Pinot Blanc and Pinot Gris are mutations of Pinot Noir and can legally be included in Bourgogne Blanc AOC blends','Pinot Blanc and Pinot Gris are prohibited from all Burgundy AOCs','Pinot Blanc dominates Mâconnais production','Pinot Gris is the main variety in Gevrey-Chambertin whites'], answer:0, explanation:'Pinot Blanc and Pinot Gris are colour mutations of Pinot Noir. They are legally permitted in some Burgundy AOCs including Bourgogne Blanc, though in practice they are rarely used — the overwhelming majority of white Burgundy is pure Chardonnay.' },
  // ── CHAMPAGNE ─────────────────────────────────────────────
  { id:'fr-ch-001', country:'France', region:'Champagne', topic:'Winemaking', difficulty:'Easy', question:'What process creates the bubbles in Champagne, distinguishing it from still wine?', options:['CO2 injection under pressure','Primary fermentation in the bottle','Secondary fermentation in the bottle (traditional method)','Carbonation through a carbonating machine'], answer:2, explanation:'Champagne is made by the traditional method (méthode champenoise): a second fermentation is triggered in the sealed bottle by adding a mixture of wine, yeast, and sugar (liqueur de tirage), producing CO2 that dissolves into the wine.' },
  { id:'fr-ch-002', country:'France', region:'Champagne', topic:'Grape Varieties', difficulty:'Easy', question:'What are the three principal grape varieties used in Champagne production?', options:['Chardonnay, Pinot Gris, Pinot Blanc','Chardonnay, Pinot Noir, Pinot Meunier','Chardonnay, Sauvignon Blanc, Pinot Noir','Pinot Noir, Gamay, Chardonnay'], answer:1, explanation:'The three main Champagne grapes are Chardonnay (white), Pinot Noir (red-skinned), and Pinot Meunier (red-skinned). Six other minor varieties (Arbane, Petit Meslier, Pinot Blanc, Pinot Gris) are also permitted but rarely used.' },
  { id:'fr-ch-003', country:'France', region:'Champagne', topic:'Styles', difficulty:'Easy', question:'What does "Blanc de Blancs" on a Champagne label indicate?', options:['The wine is made from 100% Chardonnay','The wine is a blend of Chardonnay and Pinot Blanc','The wine contains no Pinot Noir','The wine is made from all red grapes with no skin contact'], answer:0, explanation:'Blanc de Blancs means "white from whites" — the wine is made exclusively from white-skinned grapes, in practice almost always 100% Chardonnay. It tends to be more delicate, citrusy, and age-worthy than non-vintage Champagne.' },
  { id:'fr-ch-004', country:'France', region:'Champagne', topic:'Styles', difficulty:'Easy', question:'What does "Blanc de Noirs" on a Champagne label indicate?', options:['A rosé Champagne made by blending red and white wines','A white Champagne made exclusively from black-skinned grapes (Pinot Noir or Pinot Meunier)','A Champagne made exclusively from Chardonnay','A lightly coloured rosé from Pinot Meunier'], answer:1, explanation:'Blanc de Noirs is a white Champagne made entirely from black-skinned grapes (Pinot Noir and/or Pinot Meunier), with the skins removed before fermentation to avoid colour extraction. It is typically full-bodied and rich.' },
  { id:'fr-ch-005', country:'France', region:'Champagne', topic:'Styles', difficulty:'Medium', question:'What is the minimum level of residual sugar for a Champagne labelled "Brut"?', options:['Less than 3 g/L','Less than 12 g/L','Between 17 and 32 g/L','More than 50 g/L'], answer:1, explanation:'Brut Champagne must have fewer than 12 g/L residual sugar (dosage). The levels from driest to sweetest are: Brut Nature (0–3 g/L), Extra Brut (0–6), Brut (0–12), Extra Sec (12–17), Sec (17–32), Demi-Sec (32–50), Doux (50+).' },
  { id:'fr-ch-006', country:'France', region:'Champagne', topic:'Winemaking', difficulty:'Medium', question:'What is "disgorgement" (dégorgement) in Champagne production?', options:['Adding the liqueur de tirage to start secondary fermentation','Removing the yeast sediment (lees) collected after riddling, before adding dosage','The blending of reserve wines from different vintages','Adding sulphur dioxide to stabilise the wine'], answer:1, explanation:'After riddling (remuage) collects the yeast lees into the bottle neck, the neck is frozen and the frozen plug of lees is expelled under pressure during disgorgement (dégorgement). The dosage (wine and sugar) is then added before final corking.' },
  { id:'fr-ch-007', country:'France', region:'Champagne', topic:'Winemaking', difficulty:'Medium', question:'What is the purpose of the "liqueur de dosage" added to Champagne after disgorgement?', options:['To initiate the secondary fermentation in bottle','To adjust the wine\'s final sweetness level and compensate for dryness after disgorgement','To clarify the wine before bottling','To add oak character to the wine'], answer:1, explanation:'The dosage (liqueur d\'expédition) is a mixture of wine and cane sugar added after disgorgement. It tops up the bottle and adjusts the final sweetness level (determining whether the wine is Brut, Extra Sec, Demi-Sec, etc.).' },
  { id:'fr-ch-008', country:'France', region:'Champagne', topic:'Classification', difficulty:'Medium', question:'How many villages in Champagne hold Grand Cru status (rated at 100% in the échelle des crus)?', options:['5','12','17','32'], answer:2, explanation:'There are 17 Grand Cru villages (communes) in Champagne, all located in the Marne department. They historically received 100% of the agreed grape price in the échelle des crus (ladder of growths) system.' },
  { id:'fr-ch-009', country:'France', region:'Champagne', topic:'Appellations', difficulty:'Easy', question:'In which sub-region of Champagne is Chardonnay the dominant grape, running south from Épernay along a ridge of chalk?', options:['Montagne de Reims','Vallée de la Marne','Côte des Blancs','Aube (Côte des Bar)'], answer:2, explanation:'The Côte des Blancs, running south of Épernay, is predominantly planted with Chardonnay on east-facing chalk slopes. Key Grand Cru villages include Cramant, Avize, Oger, and Le Mesnil-sur-Oger.' },
  { id:'fr-ch-010', country:'France', region:'Champagne', topic:'Appellations', difficulty:'Medium', question:'In which Champagne sub-region is Pinot Noir predominantly grown on south-facing chalk slopes, and which Grand Cru village is most associated with it?', options:['Côte des Blancs (Cramant)','Vallée de la Marne (Aÿ)','Montagne de Reims (Verzenay, Verzy, Bouzy)','Côte de Sézanne'], answer:2, explanation:'The Montagne de Reims is dominated by Pinot Noir, with Grand Cru villages including Bouzy (also known for still red wine Coteaux Champenois), Ambonnay, Verzenay, and Verzy. The south-facing chalk slopes provide good sun exposure despite the northerly latitude.' },
  { id:'fr-ch-011', country:'France', region:'Champagne', topic:'Styles', difficulty:'Medium', question:'What is a "Prestige Cuvée" in Champagne, and which was the world\'s first commercially released Prestige Cuvée?', options:['A single-village Champagne; first was Cristal by Louis Roederer','A non-vintage blend aged longer than standard; first was Moët\'s Brut Impérial','A top-tier Champagne from the best grapes and vintages; first was Dom Pérignon by Moët & Chandon','A Blanc de Blancs from Grand Cru sites only; first was Taittinger Comtes de Champagne'], answer:2, explanation:'Prestige Cuvées are a producer\'s top-of-the-range Champagnes, often vintage-dated and from Grand Cru or selected sites. Dom Pérignon (Moët & Chandon, first release 1936 from 1921 vintage) is widely credited as the first commercially released Prestige Cuvée, though Cristal (originally made for Tsar Alexander II) predates it.' },
  { id:'fr-ch-012', country:'France', region:'Champagne', topic:'Winemaking', difficulty:'Hard', question:'What are "vins de réserve" in Champagne production, and why are they critical for non-vintage (NV) wines?', options:['Reserve wines are simply leftover wine from over-production, stored to reduce surplus','Reserve wines from previous vintages are blended into NV wines to maintain house style consistency across different harvest conditions','Reserve wines are held exclusively for Prestige Cuvée production','Reserve wines must legally constitute at least 50% of any NV Champagne blend'], answer:1, explanation:'Reserve wines (vins de réserve) are wines retained from previous harvests and stored in tank, barrel, or magnums. Blending reserve wines into NV Champagne allows houses to maintain a consistent house style despite vintage variation. A larger reserve stock (e.g. Krug\'s multi-vintage wines) gives greater flexibility.' },
  { id:'fr-ch-013', country:'France', region:'Champagne', topic:'Business', difficulty:'Medium', question:'What does "RM" on a Champagne label stand for, and how does this differ from "NM"?', options:['RM = Récoltant-Manipulant (grower who makes wine from own grapes); NM = Négociant-Manipulant (buys grapes and makes wine)','RM = Récoltant-Marchand (grower who sells wine wholesale); NM = Négociant-Maison (large Champagne house)','RM = Regional Merchant; NM = National Merchant','RM and NM are simply codes for sweetness level'], answer:0, explanation:'RM (Récoltant-Manipulant) growers grow their own grapes and make their own Champagne — a growing quality segment. NM (Négociant-Manipulant) houses buy grapes or must from growers, including the major Champagne houses (Moët, Krug, Bollinger, etc.).' },
  { id:'fr-ch-014', country:'France', region:'Champagne', topic:'Soils', difficulty:'Medium', question:'What type of soil is most characteristic of the Côte des Blancs and Montagne de Reims, and what is its significance for Champagne quality?', options:['Limestone clay (calcaire)','Belemnite chalk','Red basalt volcanic','Kimmeridgian marl'], answer:1, explanation:'Belemnite chalk (from the Upper Cretaceous period) is the iconic Champagne soil. It provides excellent drainage, reflects light, and retains moisture during dry periods. The Côte des Blancs sits on Belemnite chalk; the Aube has Kimmeridgian (older) chalk/marl, similar to Chablis.' },
  { id:'fr-ch-015', country:'France', region:'Champagne', topic:'Climate', difficulty:'Easy', question:'Champagne is notable for being one of the world\'s most northerly wine-producing regions. What is the main climate challenge this creates?', options:['Excessive heat in summer causing over-ripeness','Insufficient sunshine to fully ripen grapes, requiring careful site selection and viticulture','Drought due to lack of winter rainfall','Extreme summer storms damaging the chalk soils'], answer:1, explanation:'Champagne\'s northern latitude (around 49°N) means grapes struggle to ripen fully, producing high-acid, low-sugar base wines with 9–10% potential alcohol. This is actually ideal for Champagne as the secondary fermentation adds alcohol and the high acid is essential for freshness and longevity.' },
  { id:'fr-ch-016', country:'France', region:'Champagne', topic:'Wine Law', difficulty:'Medium', question:'What is the minimum lees ageing requirement for non-vintage Champagne from disgorgement to release?', options:['6 months','15 months','36 months','48 months'], answer:1, explanation:'NV Champagne must be aged for a minimum of 15 months after the liqueur de tirage is added (of which at least 12 months must be on lees). Vintage Champagne requires a minimum of 36 months on lees. Many premium houses age their NV wines significantly longer.' },
  { id:'fr-ch-017', country:'France', region:'Champagne', topic:'Business', difficulty:'Hard', question:'Which city is the commercial capital of Champagne, home to the grandes maisons (major houses) including Moët & Chandon and Veuve Clicquot?', options:['Troyes','Reims','Épernay','Hautvillers'], answer:2, explanation:'Épernay is the commercial capital of Champagne, with the prestigious "Avenue de Champagne" where the crayères (chalk cellars) of major houses — including Moët & Chandon, Perrier-Jouët, and Pol Roger — are located. Reims is a major city with historical importance (cathedral, Pommery).' },
  { id:'fr-ch-018', country:'France', region:'Champagne', topic:'Styles', difficulty:'Medium', question:'Rosé Champagne can be made by two methods. Which method is unique to Champagne among all EU sparkling wine appellations?', options:['The saignée method (brief skin contact)','Direct pressing of red grapes','Blending of red and white wines before secondary fermentation','Carbonic maceration of red grapes'], answer:2, explanation:'Blending a small amount of still red wine (Coteaux Champenois Rouge, usually Pinot Noir) with white Champagne before the secondary fermentation is unique to Champagne — it is the only EU sparkling wine appellation permitted to blend red and white wines to make rosé.' },
  { id:'fr-ch-019', country:'France', region:'Champagne', topic:'Appellations', difficulty:'Hard', question:'The Aube (Côte des Bar) is Champagne\'s southernmost sub-region. Which grape variety dominates its plantings, and what distinguishes its soil from the Marne valley?', options:['Chardonnay dominates; soil is Belemnite chalk like the Côte des Blancs','Pinot Meunier dominates; soil is sandy loam','Pinot Noir dominates; soil is Kimmeridgian limestone and marl similar to Chablis','Pinot Gris dominates; soil is volcanic basalt'], answer:2, explanation:'The Aube (Côte des Bar) is dominated by Pinot Noir (over 80% of plantings) and has Kimmeridgian limestone and marl soils — the same geological formation as Chablis — rather than the Belemnite chalk of the Marne. This gives Aube Champagnes a different character (often rounder, with red fruit).' },
  { id:'fr-ch-020', country:'France', region:'Champagne', topic:'Winemaking', difficulty:'Medium', question:'What is the purpose of "riddling" (remuage) in Champagne production?', options:['To mix the dosage evenly into the wine after disgorgement','To gradually move yeast lees to the neck of the bottle ready for disgorgement','To initiate secondary fermentation in the bottle','To clarify the base wine before secondary fermentation'], answer:1, explanation:'Riddling (remuage) involves gradually tilting and rotating the bottle over several weeks (or days using gyropalettes) until it is upside down, moving the yeast sediment from the body of the bottle into the neck, where it can be frozen and removed during disgorgement.' },
  { id:'fr-ch-021', country:'France', region:'Champagne', topic:'Styles', difficulty:'Hard', question:'What is a "solera system" Champagne or "multi-vintage" (MV) wine, and which Champagne house is most famous for this approach?', options:['A vintage Champagne blended from three consecutive years; Moët & Chandon','A Champagne made by keeping wine from every previous year in a perpetual blend, topping up with the newest vintage; Krug','A wine made by blending reserve wines from 50 years of harvests; Dom Pérignon','A single-vineyard Champagne from an individual plot; Philipponnat'], answer:1, explanation:'Krug\'s Grande Cuvée is built from a perpetual multi-vintage blend, drawing on reserves going back over 10 years (in some releases over 20). This consistency-building approach is also used by Billecart-Salmon and others. Krug is the most famous proponent of maximising reserve wine complexity.' },
  { id:'fr-ch-022', country:'France', region:'Champagne', topic:'Grape Varieties', difficulty:'Hard', question:'Pinot Meunier is important in Champagne but sometimes considered less prestigious than Chardonnay or Pinot Noir. What is its main contribution to NV blends?', options:['It provides the highest alcohol and backbone to the blend','It contributes early-drinking fruitiness, aromatic freshness, and frost resistance compared to Pinot Noir','It provides the mineral backbone and fine bubbles','It is used only in rosé Champagne production'], answer:1, explanation:'Pinot Meunier (meaning "miller\'s Pinot" — for white powder on its leaves) is Champagne\'s most planted variety. It buds later than Pinot Noir (useful for frost-prone valley areas) and contributes round, youthful, fruity character and aromatic freshness to NV blends.' },
  // ── RHÔNE VALLEY ─────────────────────────────────────────
  { id:'fr-rh-001', country:'France', region:'Rhône Valley', topic:'Grape Varieties', difficulty:'Easy', question:'Which is the sole red grape permitted in Northern Rhône AOCs such as Hermitage, Cornas, and Côte-Rôtie?', options:['Grenache','Mourvèdre','Syrah','Cabernet Sauvignon'], answer:2, explanation:'Syrah is the only permitted red grape in the Northern Rhône AOCs. It produces wines of great concentration, complexity, and ageability in appellations such as Hermitage, Cornas, Côte-Rôtie, and Crozes-Hermitage.' },
  { id:'fr-rh-002', country:'France', region:'Rhône Valley', topic:'Grape Varieties', difficulty:'Easy', question:'Which fragrant white grape variety is the sole permitted variety in Condrieu AOC, known for its aromatic, peachy wines?', options:['Marsanne','Roussanne','Viognier','Clairette'], answer:2, explanation:'Viognier is the sole permitted grape for Condrieu AOC. It produces richly aromatic whites with apricot, peach, blossom, and musk aromas, low acidity, and high alcohol. Yields must be kept low to maintain quality.' },
  { id:'fr-rh-003', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Easy', question:'Which Northern Rhône AOC is the only single-estate AOC in France, owned entirely by the Neyret-Gachet family (later Guigal)?', options:['Château-Grillet','Hermitage','L\'Ermita','Cornas'], answer:0, explanation:'Château-Grillet AOC is a single-estate AOC — one of the smallest AOCs in France — owned by the Neyret-Gachet family for generations before being sold to Marcel Guigal in 2011. It produces white wine from Viognier.' },
  { id:'fr-rh-004', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Medium', question:'What distinguishes Côte-Rôtie AOC from other Northern Rhône appellations in terms of permitted grape varieties?', options:['It permits Grenache Blanc as well as Syrah','Up to 20% Viognier may be co-fermented with Syrah','Marsanne is the dominant variety for white wine in the same appellation','It must be 100% Syrah; no white grapes are permitted'], answer:1, explanation:'Côte-Rôtie is unusual in allowing up to 20% of the white grape Viognier to be co-fermented with Syrah (not blended after — co-fermented). The Viognier adds aromatic lift, colour stability, and floral notes. In practice, most producers use very little or none.' },
  { id:'fr-rh-005', country:'France', region:'Rhône Valley', topic:'Soils', difficulty:'Medium', question:'What type of soil characterises the steep hillside vineyards of Hermitage, requiring extensive stone terracing?', options:['Chalk and limestone like Champagne','Decomposed granite on steep schist','Sandy loam over clay','Galets roulés (rounded river stones)'], answer:1, explanation:'Hermitage sits on a single granite hill above the town of Tain-l\'Hermitage. The soils are decomposed granite (grus), sometimes with schist, on very steep terraced slopes requiring extensive manual labour. The Syrah from granite produces wines of great power and mineral complexity.' },
  { id:'fr-rh-006', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Medium', question:'Which Southern Rhône appellation is the only one in France permitted to produce rosé wine exclusively — no red or white?', options:['Gigondas','Vacqueyras','Lirac','Tavel'], answer:3, explanation:'Tavel AOC, just west of Châteauneuf-du-Pape, produces only dry rosé wine. It is one of France\'s most famous rosé appellations, made from Grenache, Cinsault, Mourvèdre, and other permitted varieties. It is typically fuller-bodied than Provence rosé.' },
  { id:'fr-rh-007', country:'France', region:'Rhône Valley', topic:'Grape Varieties', difficulty:'Medium', question:'Châteauneuf-du-Pape permits up to 18 grape varieties in its appellation rules. Which variety typically dominates the blend?', options:['Mourvèdre','Syrah','Grenache','Cinsault'], answer:2, explanation:'Grenache typically dominates Châteauneuf-du-Pape blends, often comprising 60–80%+ of the wine. It provides alcohol, red fruit, and warmth. Mourvèdre adds structure and meat; Syrah adds colour and spice; Cinsault adds freshness.' },
  { id:'fr-rh-008', country:'France', region:'Rhône Valley', topic:'Soils', difficulty:'Hard', question:'What are "galets roulés" and in which Southern Rhône appellation are they most associated with?', options:['Sandy granite deposits in the Ahr Valley, Germany','Large rounded river pebbles characteristic of Châteauneuf-du-Pape vineyards','Limestone cobbles in the Languedoc','Iron-rich clay nodules found in Saint-Émilion'], answer:1, explanation:'Galets roulés are large rounded pebbles (up to 30cm diameter) deposited by ancient Rhône glaciers. They are the iconic soil of Châteauneuf-du-Pape, retaining daytime heat and radiating warmth at night, aiding Grenache ripeness. However, they only cover part of the appellation — much land is sandy or stony without the famous galets.' },
  { id:'fr-rh-009', country:'France', region:'Rhône Valley', topic:'Climate', difficulty:'Easy', question:'Which wind, blowing from the northwest, is an important climate feature of the Rhône Valley, keeping vineyards dry and reducing disease pressure?', options:['Tramontane','Levante','Mistral','Föhn'], answer:2, explanation:'The Mistral is a cold, dry, sometimes violent wind that sweeps down the Rhône Valley from the northwest. While it can damage young vines, it dries the vines quickly after rain, reducing fungal disease risk. It contributes to the Rhône\'s generally dry Mediterranean character.' },
  { id:'fr-rh-010', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Medium', question:'What distinguishes Cornas AOC from all other Northern Rhône red wine appellations?', options:['It is the only Northern Rhône appellation that permits Viognier blending','It is the only Northern Rhône red AOC requiring 100% Syrah with no white grapes permitted','It produces no red wine — only white','It uses only Grenache and Mourvèdre'], answer:1, explanation:'Cornas AOC requires 100% Syrah for its red wines, with no white grape varieties permitted (unlike Côte-Rôtie which allows Viognier, and Hermitage and Saint-Joseph which have separate white wine AOCs). It is known for very tannic, powerful, traditionally-made Syrah.' },
  { id:'fr-rh-011', country:'France', region:'Rhône Valley', topic:'Winemaking', difficulty:'Hard', question:'Hermitage Blanc is produced from which grape varieties, and how does its winemaking differ from the red Hermitage?', options:['Grenache Blanc and Bourboulenc, fermented in stainless steel only','Marsanne and Roussanne, often barrel-fermented and capable of exceptional longevity','100% Viognier fermented in cement vats','Clairette and Picpoul, usually unoaked and young-drinking'], answer:1, explanation:'White Hermitage is made from Marsanne (dominant) and Roussanne. It is often barrel-fermented and/or aged in old oak, developing golden colour, honeyed complexity, and extraordinary longevity (20–30+ years). Young, it can be closed and fat; aged, it develops mineral, lanolin, and acacia blossom complexity.' },
  { id:'fr-rh-012', country:'France', region:'Rhône Valley', topic:'Styles', difficulty:'Medium', question:'Gigondas AOC in the Southern Rhône is most known for which type of wine?', options:['Dry rosé only','Light, fruity red wines similar to Beaujolais Nouveau','Structured, Grenache-dominated red wines (rosé also permitted)','Sweet fortified Grenache wines'], answer:2, explanation:'Gigondas produces robust red wines (and some rosé) based on Grenache. Its wines are often compared to Châteauneuf-du-Pape at lower prices. Rosé is permitted in Gigondas, but white wine is not.' },
  { id:'fr-rh-013', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Medium', question:'Saint-Péray AOC in the Northern Rhône produces only white wines. What styles are permitted?', options:['Only still, dry whites from Viognier','Only sparkling wines from Syrah','Both still and sparkling whites from Marsanne and Roussanne','Only sweet late-harvest whites from Marsanne'], answer:2, explanation:'Saint-Péray produces both still and sparkling (traditional method) whites from Marsanne and Roussanne. The sparkling Saint-Péray Mousseux was historically more common; today both styles are produced.' },
  { id:'fr-rh-014', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Easy', question:'Which famous Southern Rhône AOC takes its name from a papal summer residence built in the 14th century?', options:['Gigondas','Vacqueyras','Châteauneuf-du-Pape','Lirac'], answer:2, explanation:'Châteauneuf-du-Pape means "new castle of the Pope" — named for the summer palace built there by Pope John XXII in the 14th century when the papacy was based in Avignon. It became France\'s first AOC in 1936.' },
  // ── ALSACE ───────────────────────────────────────────────
  { id:'fr-al-001', country:'France', region:'Alsace', topic:'Grape Varieties', difficulty:'Easy', question:'Which four grape varieties are known as the "noble varieties" of Alsace?', options:['Pinot Blanc, Sylvaner, Muscat, Pinot Gris','Riesling, Gewurztraminer, Pinot Gris, Muscat','Riesling, Chardonnay, Gewurztraminer, Pinot Noir','Pinot Blanc, Riesling, Pinot Noir, Gewurztraminer'], answer:1, explanation:'The four noble varieties of Alsace are Riesling, Gewurztraminer, Pinot Gris, and Muscat. These are the only varieties permitted for Alsace Grand Cru AOC and can produce Vendange Tardive (VT) and Sélection de Grains Nobles (SGN) wines.' },
  { id:'fr-al-002', country:'France', region:'Alsace', topic:'Climate', difficulty:'Easy', question:'Why does Alsace have one of the driest climates in France despite lying in the far northeast of the country?', options:['Warm Mediterranean airflow from the south protects the region','The Vosges Mountains to the west create a rain shadow effect','The Rhine river provides a warming microclimate in all seasons','The Alps divert Atlantic storms away from the region'], answer:1, explanation:'The Vosges Mountains protect Alsace from Atlantic moisture and rainfall, creating a rain shadow effect. Colmar in the Alsace plain is one of the driest cities in France (annual rainfall around 500mm). This warm, dry climate allows excellent grape ripening.' },
  { id:'fr-al-003', country:'France', region:'Alsace', topic:'Styles', difficulty:'Medium', question:'What is the difference between Vendange Tardive (VT) and Sélection de Grains Nobles (SGN) in Alsace?', options:['VT uses botrytised grapes only; SGN uses late-harvested but not botrytised grapes','VT is late-harvested (not necessarily botrytised) wine that may be dry or sweet; SGN is from individually selected botrytised berries, always very sweet','VT is a sparkling wine style; SGN is a still wine style','VT is produced from Riesling only; SGN from Gewurztraminer only'], answer:1, explanation:'Vendange Tardive wines are made from late-harvested grapes with elevated sugar levels — they may or may not be botrytised and can range from dry to sweet. SGN wines are made from individually selected botrytised berries, always very sweet and complex (similar to German TBA or Sauternes).' },
  { id:'fr-al-004', country:'France', region:'Alsace', topic:'Wine Law', difficulty:'Medium', question:'What makes Alsace AOC labelling unusual compared to most other French wine regions?', options:['Alsace labels list the commune rather than grape variety','Alsace labels are dominated by the grape variety name, unlike most French AOCs which emphasise geographic origin','All Alsace wines must show only the house name with no grape variety','Alsace wines are not permitted to show vintage on the label'], answer:1, explanation:'Unlike most French AOCs where the geographic origin is the primary label information, Alsace wines prominently display the grape variety name (e.g. "Alsace Riesling", "Alsace Gewurztraminer"). This makes them easier for consumers to identify by grape style.' },
  { id:'fr-al-005', country:'France', region:'Alsace', topic:'Classification', difficulty:'Medium', question:'How many Grand Cru vineyard sites exist in Alsace?', options:['17','33','51','52'], answer:3, explanation:'There are 51 Grand Cru sites (sometimes cited as 51–52 with the addition of Zotzenberg) in Alsace. Each Grand Cru must produce only the four noble varieties (Riesling, Gewurztraminer, Pinot Gris, Muscat). Examples include Schlossberg, Rangen, Brand, and Muenchberg.' },
  { id:'fr-al-006', country:'France', region:'Alsace', topic:'Grape Varieties', difficulty:'Medium', question:'What is the characteristic aroma descriptor most associated with Gewurztraminer from Alsace?', options:['Gooseberry and cut grass','Petrol and lime','Lychee, rose petal, and Turkish delight','Blackcurrant and cedar'], answer:2, explanation:'Gewurztraminer is famous for its intensely aromatic profile — lychee, rose petal, Turkish delight, ginger, and spice. Despite its aromatic richness, it typically has low acidity and can have naturally high alcohol. It is vinified almost always as a dry or off-dry wine in Alsace.' },
  { id:'fr-al-007', country:'France', region:'Alsace', topic:'Styles', difficulty:'Easy', question:'What type of sparkling wine is produced in Alsace using the traditional method?', options:['Champagne AOC','Alsace Mousseux','Crémant d\'Alsace','Blanquette de Limoux'], answer:2, explanation:'Crémant d\'Alsace is the traditional-method sparkling wine of the region. It is the largest-volume Crémant production in France, made from Pinot Blanc (dominant), Riesling, Auxerrois, Pinot Gris, Pinot Noir (for rosé), and Chardonnay.' },
  { id:'fr-al-008', country:'France', region:'Alsace', topic:'Grape Varieties', difficulty:'Hard', question:'Pinot Gris in Alsace is often described with which flavour profile that distinguishes it from Italian Pinot Grigio?', options:['Light, neutral, and refreshing with low alcohol','Smoky, honeyed, and full-bodied with rich texture','Strongly herbal and grassy like Sauvignon Blanc','Spicy and floral like Gewurztraminer but with higher acidity'], answer:1, explanation:'Alsace Pinot Gris is typically full-bodied, low in acidity, with smoky, honeyed, and sometimes peach/ginger character. It is richer and more complex than Italian Pinot Grigio due to later harvesting. It pairs well with foie gras and is often consumed with food.' },
  { id:'fr-al-009', country:'France', region:'Alsace', topic:'Soils', difficulty:'Hard', question:'Which statement about Alsace Grand Cru soils best explains why there are so many distinct Grand Cru sites?', options:['All Alsace Grand Crus have identical granite soils, creating a unified quality standard','Alsace sits on one of Europe\'s most geologically diverse wine regions, with individual Grand Crus varying from granite to volcanic, limestone, and clay soils','Alsace Grand Crus are distinguished by altitude alone, not soil type','Alsace soils are exclusively Kimmeridgian like Chablis'], answer:1, explanation:'The Alsace wine region sits at the junction of the Vosges, Alps, and Rhine plain, creating extraordinary geological diversity. Individual Grand Crus have soils ranging from granite (Schlossberg), volcanic (Rangen), limestone and clay (Muenchberg, Moenchberg), and gneiss. This is why Riesling expresses very differently across different Grand Crus.' },
  { id:'fr-al-010', country:'France', region:'Alsace', topic:'Grape Growing', difficulty:'Medium', question:'Why is Alsace Muscat almost always vinified dry, unlike many other regions where Muscat is used for sweet wines?', options:['Alsace law prohibits sweet Muscat wines','The Muscat varieties grown in Alsace (Muscat Blanc à Petits Grains and Muscat Ottonel) reach such high natural sugars that winemakers always intervene to stop fermentation early','Alsace traditionally vinifies Muscat dry to express its intensely aromatic grapey character; sweet styles are only made as VT or SGN','Muscat cannot develop botrytis in Alsace due to the dry climate'], answer:2, explanation:'Alsace Muscat is traditionally vinified dry (or very nearly so) to showcase its characteristic fresh, grapey aroma. The style is unusual globally — most Muscat wines are sweet. Dry Muscat pairs well with asparagus, a classic Alsatian combination.' },
  // ── LOIRE VALLEY ─────────────────────────────────────────
  { id:'fr-lo-001', country:'France', region:'Loire Valley', topic:'Appellations', difficulty:'Easy', question:'In the Loire Valley\'s Central Vineyards sub-region, which two appellations face each other across the Loire River and are both famous for Sauvignon Blanc?', options:['Vouvray and Montlouis','Sancerre and Pouilly-Fumé','Muscadet and Sancerre','Chinon and Bourgueil'], answer:1, explanation:'Sancerre (left/south bank) and Pouilly-Fumé (right/north bank) face each other across the Loire River in the Central Vineyards. Both produce dry, aromatic Sauvignon Blanc wines but with distinct terroir differences (Sancerre has flint/silex and chalk soils; Pouilly-Fumé has silex/flint and chalk/calcareous clay).' },
  { id:'fr-lo-002', country:'France', region:'Loire Valley', topic:'Grape Varieties', difficulty:'Easy', question:'Which grape variety produces the famous wines of Muscadet (Muscadet Sèvre et Maine)?', options:['Chenin Blanc','Sauvignon Blanc','Melon de Bourgogne','Muscadet Blanc'], answer:2, explanation:'Muscadet is produced from the Melon de Bourgogne grape, originally from Burgundy. The grape is neutral and relatively simple on its own, but extended lees ageing (sur lie) can develop complexity. "Muscadet" refers to the wine/appellation, not a grape variety.' },
  { id:'fr-lo-003', country:'France', region:'Loire Valley', topic:'Winemaking', difficulty:'Medium', question:'What does "sur lie" mean in the context of Muscadet production, and what does it contribute to the wine?', options:['The wine is filtered through a fine mesh before bottling to remove all yeast particles','The wine is aged on its gross and fine lees (dead yeast cells) in the same vessel used for fermentation, adding complexity and a slight natural spritz','The wine is made by blending multiple vintages to maintain consistency','The wine undergoes extended maceration on grape skins to add tannin'], answer:1, explanation:'Sur lie means "on the lees" — the wine stays in contact with its dead yeast cells (lees) from fermentation until bottling, without racking. This adds yeast-derived complexity, a creamy texture, and sometimes a slight natural pétillance (CO2 from the lees). Muscadet sur lie must age until 30 June the year after harvest at minimum.' },
  { id:'fr-lo-004', country:'France', region:'Loire Valley', topic:'Grape Varieties', difficulty:'Easy', question:'Which versatile grape variety is used for Vouvray, Savennières, Coteaux du Layon, and Saumur sparkling wines in the Loire?', options:['Sauvignon Blanc','Pinot Gris','Chenin Blanc','Viognier'], answer:2, explanation:'Chenin Blanc (called Pineau de la Loire locally) is the dominant white grape of Anjou-Saumur and Touraine, capable of producing dry, off-dry, sweet (botrytised), and sparkling wines across multiple appellations.' },
  { id:'fr-lo-005', country:'France', region:'Loire Valley', topic:'Appellations', difficulty:'Medium', question:'Which Anjou AOC produces exclusively dry white wine from Chenin Blanc, and has two special lieu-dits (individual vineyard plots) with Grand Cru status?', options:['Anjou Blanc','Saumur Blanc','Savennières','Coteaux du Layon'], answer:2, explanation:'Savennières AOC produces dry, minerally Chenin Blanc wines from vineyards on schist soils near Angers. Two Grands Crus exist within it: Coulée de Serrant (a monopole owned by Nicolas Joly, a biodynamic pioneer) and Roche aux Moines.' },
  { id:'fr-lo-006', country:'France', region:'Loire Valley', topic:'Appellations', difficulty:'Easy', question:'Which central Loire appellation, based on Cabernet Franc, is known for elegantly structured red wines from tuffeau (tufa limestone) and sandy soils?', options:['Bourgueil','Chinon','Saumur-Champigny','Sancerre Rouge'], answer:1, explanation:'Chinon AOC (Indre-et-Loire, around the town of Chinon) produces red wines from Cabernet Franc, with different styles depending on soil: tuffeau soils produce more structured, ageworthy reds; sandy soils produce lighter, earlier-drinking wines. Rabelais\' home region.' },
  { id:'fr-lo-007', country:'France', region:'Loire Valley', topic:'Styles', difficulty:'Medium', question:'Vouvray AOC (Chenin Blanc, Touraine) can be produced in which range of styles?', options:['Only dry (sec) and sparkling','Dry, off-dry, medium-sweet, sweet (moelleux), and traditional method sparkling','Only sweet (moelleux) and sparkling','Only dry and pétillant naturel'], answer:1, explanation:'Vouvray AOC covers the full spectrum from bone dry (sec) to off-dry (demi-sec) to medium-sweet to fully sweet (moelleux — made from botrytised or passerillage grapes) and traditional method sparkling (Vouvray Mousseux). The Chenin Blanc grape\'s high acidity makes it suitable for all styles.' },
  { id:'fr-lo-008', country:'France', region:'Loire Valley', topic:'Appellations', difficulty:'Medium', question:'Which Anjou sub-appellation produces some of Loire\'s most celebrated sweet wines from botrytised Chenin Blanc, and has two sub-AOCs with Grand Cru status?', options:['Bonnezeaux and Quarts de Chaume within Coteaux du Layon','Vouvray Moelleux and Montlouis-sur-Loire','Savennières and Anjou Blanc','Muscadet Grand Cru and Coteaux de la Loire'], answer:0, explanation:'Coteaux du Layon produces sweet Chenin Blanc wines from the Layon valley near Angers. Two sites have their own Grand Cru AOCs: Bonnezeaux (south-facing, schist, very concentrated) and Quarts de Chaume (the only Chenin Blanc Grand Cru AOC), both producing luscious botrytised or late-harvest wines.' },
  { id:'fr-lo-009', country:'France', region:'Loire Valley', topic:'Appellations', difficulty:'Easy', question:'Muscadet Sèvre et Maine is the most prestigious sub-appellation of Muscadet. In which part of the Loire Valley is it located?', options:['Central Vineyards (around Sancerre)','Anjou-Saumur (around Angers)','Pays Nantais (around Nantes)','Touraine (around Tours)'], answer:2, explanation:'Muscadet and its sub-appellations (Muscadet Sèvre et Maine, Muscadet Côtes de Grandlieu, Muscadet Coteaux de la Loire) are in the Pays Nantais, the westernmost Loire Valley sub-region closest to the Atlantic coast, around the city of Nantes.' },
  { id:'fr-lo-010', country:'France', region:'Loire Valley', topic:'Climate', difficulty:'Medium', question:'Why do the Central Vineyards (Sancerre, Pouilly-Fumé) experience a more continental climate than the Pays Nantais?', options:['The Central Vineyards are at higher altitude with colder temperatures year-round','The Central Vineyards are far inland from the Atlantic, losing maritime moderating influence and experiencing colder winters and hotter summers','The Central Vineyards are further north and receive less sunshine','The Central Vineyards are protected by the Massif Central from all weather systems'], answer:1, explanation:'The Loire Valley stretches over 300km from Nantes (Atlantic coast) to the Central Vineyards (Sancerre/Pouilly-Fumé). The eastern end is far inland, making the climate more continental (colder winters, hotter summers, more variable). Nantes benefits from Atlantic moderation.' },
  { id:'fr-lo-011', country:'France', region:'Loire Valley', topic:'Soils', difficulty:'Hard', question:'What is "silex" (flint) soil in the context of Sancerre and Pouilly-Fumé, and what flavour does it supposedly impart?', options:['Silex is a compacted limestone clay giving Sauvignon Blanc its green pepper character','Silex is pure flint soil giving a smoky, mineral, gunflint-like quality to the wine; the "Fumé" in Pouilly-Fumé references this character','Silex is the volcanic basalt found under Grand Cru Sancerre vineyards','Silex is the Kimmeridgian limestone that gives the wines their high acidity'], answer:1, explanation:'Silex (flint) soil is particularly associated with Pouilly-Fumé and parts of Sancerre. The "Fumé" in Pouilly-Fumé is said to refer to both the gunflint/smoky aroma from silex soils and the morning mist over the Loire. Sancerre has three main soils: silex (flint), caillotes (limestone), and terres blanches (Kimmeridgian marl, like Chablis).' },
  { id:'fr-lo-012', country:'France', region:'Loire Valley', topic:'Grape Varieties', difficulty:'Medium', question:'Which red grape variety produces Sancerre Rouge and Sancerre Rosé, and is also grown in Touraine for Chinon, Bourgueil, and Saumur-Champigny?', options:['Gamay','Pinot Noir (in Sancerre); Cabernet Franc (in Touraine)','Cabernet Franc throughout the Loire Valley','Malbec (Côt)'], answer:1, explanation:'Sancerre Rouge and Rosé are made from Pinot Noir. Touraine red wines (Chinon, Bourgueil, Saumur-Champigny) are made from Cabernet Franc. These are the dominant red varieties in their respective Loire sub-regions.' },
  // ── LANGUEDOC-ROUSSILLON ─────────────────────────────────
  { id:'fr-lr-001', country:'France', region:'Languedoc-Roussillon', topic:'Appellations', difficulty:'Easy', question:'Which Languedoc appellation is known for its white wine from Piquepoul Blanc grapes, often consumed with oysters from the nearby étang (lagoon)?', options:['Faugères','Limoux','Picpoul de Pinet','Corbières Blanc'], answer:2, explanation:'Picpoul de Pinet AOC (Hérault) produces light, crisp, high-acid white wine from Piquepoul Blanc (Picpoul Blanc). It is grown around the Bassin de Thau, a lagoon famous for oyster farming, and the wine is a classic pairing.' },
  { id:'fr-lr-002', country:'France', region:'Languedoc-Roussillon', topic:'Appellations', difficulty:'Medium', question:'Which Languedoc appellation is unusual for its schist (shale) soils, which impart mineral character to its predominantly Grenache, Syrah, and Mourvèdre red wines?', options:['Corbières','Minervois','Faugères','La Clape'], answer:2, explanation:'Faugères AOC, in the western Hérault, sits almost entirely on schist (shale) soils — very unusual in the Languedoc where limestone dominates. This gives Faugères wines a distinctive mineral, earthy quality. Saint-Chinian (adjacent appellation) also has some schist areas.' },
  { id:'fr-lr-003', country:'France', region:'Languedoc-Roussillon', topic:'Styles', difficulty:'Medium', question:'What type of wine is Banyuls, and from which area is it produced?', options:['A dry rosé wine from the Corbières hills near Narbonne','A Vin Doux Naturel (VDN) from Grenache, produced on steep schist terraces near Collioure on the Mediterranean coast','A traditional method sparkling wine from the Aude valley','A fortified sweet wine from Muscat grown on the limestone plains of the Hérault'], answer:1, explanation:'Banyuls is a Vin Doux Naturel (VDN) produced from Grenache (minimum 50%) on steep terraced schist vineyards around Banyuls-sur-Mer near the Spanish border (Roussillon). It can be tawny (rancio, oxidative) or vintage-dated. It pairs classically with chocolate.' },
  { id:'fr-lr-004', country:'France', region:'Languedoc-Roussillon', topic:'Wine Law', difficulty:'Medium', question:'What does "IGP Pays d\'Oc" represent in the Languedoc, and why is it commercially significant?', options:['It is the regional Grand Cru designation for the best Languedoc sites','It is a flexible varietal wine category allowing international varieties (Chardonnay, Merlot, Cabernet Sauvignon, Viognier) labeled by grape variety from the broad Languedoc-Roussillon zone','It is a strictly regulated appellation for traditional Southern French varieties only','It is an experimental classification for organic wines only'], answer:1, explanation:'IGP Pays d\'Oc is the broad regional Indication Géographique Protégée covering the Languedoc-Roussillon. It allows single-variety labelling including international varieties, is produced in very large quantities, and is commercially very significant for French wine exports — especially Chardonnay, Merlot, and Sauvignon Blanc labeled by variety.' },
  { id:'fr-lr-005', country:'France', region:'Languedoc-Roussillon', topic:'Grape Varieties', difficulty:'Easy', question:'Which traditional Southern French grape variety, often grown as old bush vines in the Languedoc, is valued for its contribution to structured, full-bodied red blends and is being revived in quality winemaking?', options:['Merlot','Chardonnay','Carignan','Viognier'], answer:2, explanation:'Carignan is the most planted variety in the Languedoc historically (though declining). Old vine Carignan (50–100+ years) produces concentrated, complex wines with high acidity and tannin. Young vine Carignan is inferior. It is increasingly valued as an "old vine" ingredient in premium Languedoc blends.' },
  { id:'fr-lr-006', country:'France', region:'Languedoc-Roussillon', topic:'Appellations', difficulty:'Medium', question:'What is the Languedoc\'s most southerly and geographically largest AOC, covering most of the Hérault, Gard, and Aude departments?', options:['Corbières','AOP Languedoc (formerly AOP Coteaux du Languedoc)','Minervois La Livinière','Limoux'], answer:1, explanation:'AOP Languedoc (renamed from Coteaux du Languedoc in 2007) is the umbrella appellation for much of the region. Sub-appellations (Pic Saint-Loup, Terrasses du Larzac, La Clape, etc.) can be listed on the label within the broader Languedoc AOC.' },
  { id:'fr-lr-007', country:'France', region:'Languedoc-Roussillon', topic:'Appellations', difficulty:'Hard', question:'Limoux AOC in the Aude is historically significant for sparkling wine. What is the oldest sparkling wine produced there, and from which grape?', options:['Crémant de Limoux from Chardonnay','Blanquette de Limoux from Mauzac (Blanquette), claimed to predate Champagne','Méthode Rurale from Chenin Blanc','Limoux Mousseux from Pinot Noir'], answer:1, explanation:'Blanquette de Limoux claims to be the oldest sparkling wine in France, made by monks at the Abbey of Saint-Hilaire in 1531 (before Dom Pérignon). It uses primarily Mauzac (minimum 90%), with Chenin Blanc and Chardonnay. Crémant de Limoux is a separate, higher-quality category using more Chardonnay.' },
  { id:'fr-lr-008', country:'France', region:'Languedoc-Roussillon', topic:'Climate', difficulty:'Easy', question:'What is the dominant climate type in the Languedoc-Roussillon?', options:['Continental with cold winters','Maritime Atlantic','Mediterranean with hot, dry summers and mild winters','Sub-alpine with cool temperatures year-round'], answer:2, explanation:'Languedoc-Roussillon has a classic Mediterranean climate: hot, dry summers, mild winters, and low rainfall concentrated in spring and autumn. The Tramontane and Mistral winds are important. This makes irrigation restrictions less of an issue in wet years but drought stress is a risk.' },
  // ── BEAUJOLAIS ───────────────────────────────────────────
  { id:'fr-bj-001', country:'France', region:'Beaujolais', topic:'Grape Varieties', difficulty:'Easy', question:'Which grape variety is used for all red wines in the Beaujolais AOC?', options:['Pinot Noir','Gamay','Syrah','Cinsault'], answer:1, explanation:'Gamay (specifically Gamay Noir à Jus Blanc) is the sole red grape of Beaujolais. It thrives on the granite soils of the northern Crus and produces wines ranging from light and fruity to complex and ageworthy (in the case of the best Crus).' },
  { id:'fr-bj-002', country:'France', region:'Beaujolais', topic:'Winemaking', difficulty:'Easy', question:'What is carbonic maceration, used widely in Beaujolais production?', options:['Whole-bunch fermentation of grapes in an atmosphere of CO2, producing light fruity wines with low tannin','Fermenting only the free-run juice of crushed grapes under CO2','Adding CO2 to wine after fermentation to create bubbles','Using a closed tank under pressure to increase extraction'], answer:0, explanation:'Carbonic maceration involves placing whole, uncrushed grape bunches in a CO2-filled tank. Fermentation begins inside each grape cell (intracellular fermentation), producing characteristic banana, bubblegum, and red fruit aromas with low tannin. The style makes wines ready to drink very young.' },
  { id:'fr-bj-003', country:'France', region:'Beaujolais', topic:'Classification', difficulty:'Medium', question:'How many Crus du Beaujolais exist, and what makes them distinct from basic Beaujolais?', options:['5 Crus; they use Pinot Noir instead of Gamay','10 Crus; they are defined geographically from the best granite-soil villages in the north and may not use the word "Beaujolais" on the label','15 Crus; they are classified by the French government as Premier Cru','7 Crus; they must use extended oak ageing like Burgundy'], answer:1, explanation:'There are 10 Crus du Beaujolais: Moulin-à-Vent, Fleurie, Morgon, Brouilly, Côte de Brouilly, Régnié, Juliénas, Chénas, Saint-Amour, and Chiroubles. They are all from the northern granite-soil area and typically do not use "Beaujolais" on the label — they just use their own Cru name.' },
  { id:'fr-bj-004', country:'France', region:'Beaujolais', topic:'Styles', difficulty:'Easy', question:'Beaujolais Nouveau is released on the third Thursday of November each year. What style of wine is it?', options:['A structured, oak-aged wine from the best Cru villages','A light, fruity, young wine released weeks after harvest, using carbonic maceration','A sweet, botrytised Gamay wine','A sparkling Gamay wine made by the traditional method'], answer:1, explanation:'Beaujolais Nouveau is a young, fresh, fruity wine released just weeks after the harvest (third Thursday of November). Made from Gamay using carbonic maceration, it is typically light, low in tannin, with banana and red cherry aromas. It is meant to be consumed immediately.' },
  { id:'fr-bj-005', country:'France', region:'Beaujolais', topic:'Soils', difficulty:'Medium', question:'How do the soils of the southern Beaujolais differ from the northern Cru villages?', options:['Southern Beaujolais has granite soils; northern Crus have clay-limestone','Southern Beaujolais has clay-limestone soils (similar to southern Burgundy); northern Crus have granite and schist','All Beaujolais has identical granite soils throughout','Northern and southern Beaujolais both have volcanic basalt'], answer:1, explanation:'Northern Beaujolais (Crus area) has granite and gneiss soils — ideal for structured, complex Gamay. Southern Beaujolais has clay-limestone soils (similar to the Mâconnais to the north), better suited to lighter, simpler wines for Beaujolais AOC and Beaujolais-Villages.' },
  // ── PROVENCE ─────────────────────────────────────────────
  { id:'fr-pr-001', country:'France', region:'Provence', topic:'Styles', difficulty:'Easy', question:'Which wine style dominates Côtes de Provence AOC production, making Provence one of the world\'s leading producers of this style?', options:['Full-bodied red wines','Dry rosé wines','Sweet Muscat wines','Sparkling traditional method wines'], answer:1, explanation:'Provence produces approximately 90% rosé wine, making it France\'s largest rosé-producing region and a global benchmark for dry Provence rosé. The pale salmon colour, delicate fruit, and dry crisp finish are the signature style.' },
  { id:'fr-pr-002', country:'France', region:'Provence', topic:'Appellations', difficulty:'Medium', question:'Which Provence AOC requires Mourvèdre to make up the majority of red wine production and mandates minimum ageing?', options:['Côtes de Provence','Coteaux d\'Aix-en-Provence','Bandol','Cassis'], answer:2, explanation:'Bandol AOC requires a minimum of 50% Mourvèdre in its red wines (one of the few AOCs where Mourvèdre is compulsory at such levels) with at least 18 months ageing in wood. Bandol reds are highly regarded and can age for decades.' },
  // ── SOUTH-WEST FRANCE ────────────────────────────────────
  { id:'fr-sw-001', country:'France', region:'South-West France', topic:'Appellations', difficulty:'Medium', question:'Cahors AOC is often called the "Black Wine." Which grape variety must constitute at least 70% of the blend?', options:['Tannat','Fer Servadou','Malbec (Côt/Auxerrois)','Négrette'], answer:2, explanation:'Cahors AOC requires a minimum of 70% Malbec (locally called Côt or Auxerrois) — this is the grape from which Argentinian Malbec is derived. Historically Cahors was very tannic and dark ("black wine"); today styles range from modern and approachable to traditional and structured.' },
  { id:'fr-sw-002', country:'France', region:'South-West France', topic:'Winemaking', difficulty:'Hard', question:'Madiran AOC uses Tannat as its main red variety. Which winemaking technique was invented at Domaine Brana specifically to soften Tannat\'s exceptionally high tannins?', options:['Flash détente','Micro-oxygenation, invented by Patrick Ducournau','Carbonic maceration','Cryo-extraction'], answer:1, explanation:'Micro-oxygenation was invented in 1991 by Patrick Ducournau in Madiran to soften Tannat\'s aggressive tannins by slowly introducing tiny amounts of oxygen into wine (mimicking the effect of barrel ageing). The technique is now used globally.' },
  { id:'fr-sw-003', country:'France', region:'South-West France', topic:'Appellations', difficulty:'Medium', question:'Jurançon AOC in the Pyrenean foothills produces white wines from which two principal grape varieties?', options:['Tannat and Cabernet Franc','Gros Manseng and Petit Manseng','Sauvignon Blanc and Sémillon','Mauzac and Len de l\'El'], answer:1, explanation:'Jurançon AOC produces dry whites (Jurançon Sec) and sweet whites (Jurançon) from Petit Manseng (for the richest sweet wines, late-harvested with natural passerillage/drying on the vine) and Gros Manseng (for dry and lighter sweet wines). The appellation is in Béarn, near Pau.' },
  { id:'fr-sw-004', country:'France', region:'South-West France', topic:'Appellations', difficulty:'Easy', question:'Which South-West France appellation sits within the Madiran AOC zone and produces white wines from Arrufiac, Petit Courbu, Gros Manseng, and Petit Manseng?', options:['Jurançon Blanc','Pacherenc du Vic-Bilh','Irouléguy Blanc','Côtes de Gascogne'], answer:1, explanation:'Pacherenc du Vic-Bilh AOC is produced in the same geographical area as Madiran, from white indigenous varieties including Arrufiac, Petit Courbu, Gros Manseng, and Petit Manseng. It can be dry or sweet.' },
  // ── MORE BORDEAUX ─────────────────────────────────────────
  { id:'fr-bx-041', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Medium', question:'Which Bordeaux appellation specialises entirely in sweet white wine and shares its southern border with Sauternes?', options:['Cadillac','Loupiac','Sainte-Croix-du-Mont','Cérons'], answer:2, explanation:'Sainte-Croix-du-Mont, Loupiac, and Cadillac all produce sweet white wines on the right bank of the Garonne, opposite Sauternes. Sainte-Croix-du-Mont is considered the finest of these satellite sweet wine appellations.' },
  { id:'fr-bx-042', country:'France', region:'Bordeaux', topic:'Winemaking', difficulty:'Medium', question:'What is "micro-oxygenation" as applied in Bordeaux, and what problem does it solve?', options:['Pumping wine through a fine filter to remove oxygen','A controlled introduction of tiny oxygen bubbles into wine to soften tannins and stabilise colour, mimicking slow barrel ageing','A vacuum technique to remove oxygen before bottling','The natural oxidation that occurs during harvest of botrytised grapes'], answer:1, explanation:'Micro-oxygenation (MOX), invented in Madiran and adopted in Bordeaux, introduces controlled micro-bubbles of oxygen into wine. It polymerises tannins (making them softer), stabilises colour, and reduces reductive off-aromas — useful for wines in large tank that would otherwise have no barrel contact.' },
  { id:'fr-bx-043', country:'France', region:'Bordeaux', topic:'Classification', difficulty:'Hard', question:'Pétrus is arguably the most valuable wine in Bordeaux, yet it holds no official classification. Which statement explains this?', options:['Pétrus applied but was rejected from the 1855 classification','Pomerol has never had an official classification; Pétrus\'s reputation rests entirely on its consistent quality','Pétrus is classified as Premier Grand Cru Classé A in the Pomerol classification','Pétrus was downgraded from its original classification in 1960'], answer:1, explanation:'Pomerol has no official classification — unlike Médoc (1855) or Saint-Émilion (periodic). Pétrus commands prices rivalling or exceeding any classified growth purely on its extraordinary reputation for quality, the unique iron-rich clay of its plateau, and its almost exclusively Merlot production.' },
  { id:'fr-bx-044', country:'France', region:'Bordeaux', topic:'Business', difficulty:'Medium', question:'What does a "second wine" mean in Bordeaux, and which is the most famous example from a First Growth?', options:['A wine made in a second vintage if the harvest is poor','A lighter wine made from younger vines or less-selected parcels of a château, sold at lower prices; Les Forts de Latour is the most famous','A wine from the second-classified château in the Médoc hierarchy','A wine released for drinking before the grand vin but from the same vintage blend'], answer:1, explanation:'Most top Bordeaux châteaux produce a "second wine" (deuxième vin) from younger vines, different plots, or barrels not selected for the grand vin. Les Forts de Latour (Château Latour), Pavillon Rouge (Margaux), and Carruades de Lafite (Lafite Rothschild) are famous examples. They offer a more accessible entry point to the château style.' },
  { id:'fr-bx-045', country:'France', region:'Bordeaux', topic:'Grape Growing', difficulty:'Medium', question:'Which vine training system is predominant in Bordeaux, using a double Guyot or spur pruning along a single wire?', options:['Gobelet (bush vine)','Pergola (high canopy)','Double Guyot or Guyot Medoc on trellis','Lenz Moser high culture'], answer:2, explanation:'Guyot (single or double) trellis training is standard in Bordeaux. Double Guyot allows two canes of the previous year\'s wood to be trained horizontally, which is suited to the region\'s high-yielding varieties. Vine density is typically 6,500–10,000 vines per hectare in premium areas.' },
  // ── MORE BURGUNDY ─────────────────────────────────────────
  { id:'fr-bu-041', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Hard', question:'What is the "Maranges" AOC, and where is it located in the Burgundy hierarchy?', options:['A Grand Cru appellation between Beaune and Gevrey-Chambertin','A Côte de Beaune communal appellation at the southern tip, known for affordable Pinot Noir and Chardonnay from three communes','A Côte Chalonnaise village appellation for Aligoté','A Mâconnais village appellation for Chardonnay only'], answer:1, explanation:'Maranges AOC is at the far southern end of the Côte de Beaune, covering the communes of Sampigny-lès-Maranges, Dezize-lès-Maranges, and Cheilly-lès-Maranges. It has Premier Cru vineyards and is known for relatively affordable Pinot Noir and some Chardonnay.' },
  { id:'fr-bu-042', country:'France', region:'Burgundy', topic:'Classification', difficulty:'Medium', question:'What is a Burgundy "monopole" Grand Cru and which domaine controls Romanée-Conti Grand Cru (4.5 hectares)?', options:['Domaine Leroy','Domaine Leflaive','Domaine de la Romanée-Conti (DRC)','Domaine Armand Rousseau'], answer:2, explanation:'Romanée-Conti Grand Cru is a monopole entirely owned by Domaine de la Romanée-Conti (DRC). At 4.5 hectares, it produces approximately 5,000–6,000 bottles annually of some of the world\'s most expensive wines (often €10,000–30,000+ per bottle).' },
  { id:'fr-bu-043', country:'France', region:'Burgundy', topic:'Winemaking', difficulty:'Hard', question:'What does "élevage" mean in the context of Burgundy winemaking?', options:['The selection of the best barrels for the Grand Vin','The process of raising and nurturing wine from fermentation through to bottling — encompassing barrel ageing, topping, racking, fining, and bottling decisions','A French term for green harvest','The blending of different Premier Cru parcels before bottling'], answer:1, explanation:'Élevage (literally "raising" or "upbringing") encompasses all winemaking care from after fermentation through to bottling: barrel type and size selection, the duration of ageing, topping up evaporation, decisions about racking and lees contact, fining, and filtration. It is as important as winemaking in determining the final wine\'s character.' },
  { id:'fr-bu-044', country:'France', region:'Burgundy', topic:'Appellations', difficulty:'Medium', question:'What is "Bourgogne Côte d\'Or" AOC, introduced in 2017, and why was it created?', options:['A new Grand Cru designation for previously unclassified sites in the Côte d\'Or','A regional Burgundy appellation restricted to grapes from the Côte d\'Or, sitting above broad Bourgogne AOC but below Village wines in terms of typicity','A replacement for all Côte d\'Or Village appellations','A new appellation for orange wines made from Pinot Gris in Burgundy'], answer:1, explanation:'Bourgogne Côte d\'Or AOC was created in 2017 as a step between the broad Bourgogne AOC (can come from anywhere in Burgundy) and Village appellations. It is restricted to grapes from the Côte d\'Or and allows producers to indicate this premium geographical origin on regional wines.' },
  { id:'fr-bu-045', country:'France', region:'Burgundy', topic:'Styles', difficulty:'Medium', question:'What distinguishes the style of red wines from Morey-Saint-Denis from those of neighbouring Gevrey-Chambertin and Chambolle-Musigny?', options:['Morey-Saint-Denis produces the lightest, most delicate reds in the Côte de Nuits','Morey-Saint-Denis sits between the power of Gevrey and the finesse of Chambolle, often with a mix of structure and perfume','Morey-Saint-Denis produces exclusively white wines','Morey-Saint-Denis wines are the most tannic and structured in all of Burgundy'], answer:1, explanation:'Morey-Saint-Denis sits between Gevrey-Chambertin (powerful, tannic) and Chambolle-Musigny (delicate, floral). Its wines often exhibit a middle path — more structured than Chambolle but more perfumed than Gevrey. It has five Grand Crus: Clos de la Roche, Clos Saint-Denis, Clos des Lambrays, Clos de Tart, and part of Bonnes-Mares.' },
  // ── MORE CHAMPAGNE ────────────────────────────────────────
  { id:'fr-ch-023', country:'France', region:'Champagne', topic:'Business', difficulty:'Medium', question:'Approximately what proportion of total Champagne production do the large Négociant-Manipulant (NM) houses represent?', options:['About 20% of production but 70%+ of value and exports','About 90% of production with the rest from RM growers','Equal split: 50% NM houses, 50% RM growers','NM houses represent only niche luxury; most is RM'], answer:0, explanation:'The major Champagne houses (Négociant-Manipulant) represent about 70–80% of exports by value despite owning only about 13% of vineyard land. They buy grapes from the many thousands of small growers (récoltants), allowing them to produce very large volumes with consistent quality.' },
  { id:'fr-ch-024', country:'France', region:'Champagne', topic:'Winemaking', difficulty:'Hard', question:'What is the "dégorgement à la glace" technique for removing yeast sediment from Champagne?', options:['Blasting the bottle with liquid nitrogen to freeze the lees','Freezing the neck of the bottle in a brine or glycol solution so the frozen plug of lees is expelled by the internal pressure upon opening','Manually removing the lees with a syringe','Using a centrifuge to spin lees to the neck of the bottle'], answer:1, explanation:'In modern disgorgement, the neck of the bottle (tilted downwards after riddling) is briefly dipped in freezing brine or glycol (-25 to -30°C), freezing a small plug of wine and lees. When the cap is removed, the internal pressure from CO2 expels the frozen plug, leaving clear wine behind.' },
  { id:'fr-ch-025', country:'France', region:'Champagne', topic:'Styles', difficulty:'Medium', question:'What does "récemment dégorgé" (RD) on a Champagne label indicate, and which house popularised this?', options:['The wine was blended from recently disgorged reserve wines by the négociant','The Champagne was aged for an extended period on its lees, only recently disgorged; associated with Bollinger','A Champagne that has no dosage added after disgorgement','A Champagne from the most recently released vintage'], answer:1, explanation:'"RD" (Récemment Dégorgé = Recently Disgorged) refers to Champagne that has been aged on lees for much longer than standard (often 6–10+ years for vintage wines) and only recently disgorged, preserving maximum freshness and complexity. Bollinger popularised the concept with Bollinger RD.' },
  { id:'fr-ch-026', country:'France', region:'Champagne', topic:'Grape Growing', difficulty:'Hard', question:'Which of Champagne\'s three major sub-regions has the highest proportion of Pinot Meunier plantings, and why?', options:['Côte des Blancs, because Pinot Meunier suits chalk soils','Vallée de la Marne, because Pinot Meunier\'s late budding reduces frost risk in the frost-prone river valley','Montagne de Reims, because Pinot Meunier produces the richest wines on north-facing slopes','Côte de Sézanne, which is too cold for Pinot Noir and Chardonnay'], answer:1, explanation:'Pinot Meunier dominates the Vallée de la Marne because it buds later than Pinot Noir and Chardonnay, reducing its vulnerability to spring frosts in the lower, frost-prone river valley floor. Clay-rich soils in parts of the Marne valley also suit Meunier better.' },
  // ── MORE RHÔNE ────────────────────────────────────────────
  { id:'fr-rh-015', country:'France', region:'Rhône Valley', topic:'Appellations', difficulty:'Medium', question:'Which two single-vineyard Côte-Rôtie wines made by Guigal (Les Grandes Maisons) are so famous they have achieved cult status and near-impossible prices?', options:['Les Bézards and Les Caillouets','La Landonne, La Mouline, and La Turque (the "La La La" wines)','Jaboulet\'s Hermitage La Chapelle and Chave\'s Cuvée Cathelin','Chapoutier\'s Hermitage Le Pavillon and L\'Ermite'], answer:1, explanation:'Guigal\'s single-vineyard Côte-Rôtie wines — La Landonne, La Mouline, and La Turque (nicknamed the "La La La" wines) — receive extraordinary critical scores (often 100 points) and command very high prices. They are produced in tiny quantities and aged in 100% new oak for 42 months.' },
  { id:'fr-rh-016', country:'France', region:'Rhône Valley', topic:'Grape Varieties', difficulty:'Medium', question:'Which two white grape varieties are most commonly planted in the Northern Rhône for white wine production, often as single-variety wines or blends?', options:['Grenache Blanc and Bourboulenc','Clairette and Picpoul','Marsanne and Roussanne','Roussette and Jacquère'], answer:2, explanation:'Marsanne and Roussanne are the primary white varieties of the Northern Rhône. Marsanne is more widely planted (broader, richer, can age extraordinarily well) while Roussanne is more aromatic and delicate. They are made as single-variety wines (e.g. Hermitage Blanc can be pure Marsanne) or blended together.' },
  { id:'fr-rh-017', country:'France', region:'Rhône Valley', topic:'Styles', difficulty:'Medium', question:'Crozes-Hermitage AOC surrounds the famous Hermitage hill. How do Crozes-Hermitage wines typically compare to Hermitage?', options:['Crozes-Hermitage produces only white wines; Hermitage only red','Crozes-Hermitage is larger with more varied soils, producing lighter, earlier-drinking wines; Hermitage is more concentrated and age-worthy','Crozes-Hermitage has the same quality as Hermitage but at lower yields','Crozes-Hermitage and Hermitage wines are indistinguishable in quality'], answer:1, explanation:'Crozes-Hermitage AOC is much larger than Hermitage, covering flat plains and gentler slopes as well as some better hillside sites. Its wines (red from Syrah, white from Marsanne/Roussanne) are typically lighter, approachable younger, and less concentrated than Hermitage. Quality ranges from basic to excellent from the best sites.' },
  { id:'fr-rh-018', country:'France', region:'Rhône Valley', topic:'Winemaking', difficulty:'Hard', question:'What is "rancio" in the context of Banyuls and other oxidatively aged fortified wines?', options:['A Spanish term for a fault caused by cork taint','A characteristic nutty, rancid-fat, dried fruit oxidative flavour developed in fortified wines aged in small, partially filled barrels or glass bonbonnes exposed to heat','The term for the solera system used in Banyuls production','A style of wine made from Grenache that has undergone carbonic maceration'], answer:1, explanation:'Rancio is a distinctive flavour descriptor (nutty, caramelised, dried fruit, almost rancid-fat quality) developed in fortified wines aged oxidatively in partially filled small casks or glass carboys (bonbonnes) exposed to sun and heat. It is characteristic of aged Banyuls, Maury, Rivesaltes, and VDNs from the Southern Rhône/Languedoc.' },
  // ── MORE LOIRE ────────────────────────────────────────────
  { id:'fr-lo-013', country:'France', region:'Loire Valley', topic:'Appellations', difficulty:'Medium', question:'What is the full name of the Loire sparkling wine appellation that produces Chenin Blanc wines by the traditional method in the Anjou-Saumur zone?', options:['Crémant de Loire','Saumur Mousseux and Crémant de Loire (different but related)','Vouvray Mousseux only','Touraine Mousseux'], answer:1, explanation:'Both Crémant de Loire and Saumur Mousseux are traditional-method sparkling wines from the Anjou-Saumur zone. Crémant de Loire covers a wider area and requires lower yields and more lees ageing. Vouvray Mousseux is a separate appellation for Touraine. Loire is France\'s second largest traditional-method sparkling wine region.' },
  { id:'fr-lo-014', country:'France', region:'Loire Valley', topic:'Styles', difficulty:'Easy', question:'Which Loire appellation around the Chinon and Bourgueil area is known as the Loire\'s primary red wine region, using Cabernet Franc to produce wines with violet and red fruit character?', options:['Muscadet Sèvre et Maine','Sancerre','Chinon, Bourgueil, and Saint-Nicolas-de-Bourgueil (Loire reds)','Anjou Rouge'], answer:2, explanation:'Chinon, Bourgueil, and Saint-Nicolas-de-Bourgueil are the main red wine appellations of the Loire\'s Touraine sub-region, all based on Cabernet Franc. They produce wines ranging from light, chillable styles to structured, ageworthy versions depending on soil (tuffeau vs. sand).' },
  { id:'fr-lo-015', country:'France', region:'Loire Valley', topic:'Topography', difficulty:'Medium', question:'The Loire is the longest river in France. How does the topography of the river valley influence wine styles along its length?', options:['The river makes all Loire wines identical in style regardless of location','The upper Loire (Central Vineyards) is continental and specialises in Sauvignon Blanc; the middle Loire (Anjou-Touraine) is more temperate with Chenin Blanc and Cabernet Franc; the lower Loire (Pays Nantais) is maritime with Melon de Bourgogne','The Loire river only influences the eastern Central Vineyards section','The river creates warmer conditions near the sea and cooler conditions inland, the opposite of most river valleys'], answer:1, explanation:'The Loire\'s 300+km of wine country creates dramatic diversity: the far inland Central Vineyards have a continental climate perfect for aromatic Sauvignon Blanc (Sancerre, Pouilly-Fumé); the middle Loire has a more temperate climate for versatile Chenin Blanc; the Atlantic-influenced Pays Nantais produces light, neutral Muscadet.' },
  { id:'fr-lo-016', country:'France', region:'Loire Valley', topic:'Winemaking', difficulty:'Hard', question:'Nicolas Joly of Coulée de Serrant (Savennières) is one of the world\'s most prominent advocates of which viticultural philosophy?', options:['Micro-oxygenation and technological winemaking','Biodynamic viticulture, treating the vineyard as a self-sustaining organism aligned with cosmic rhythms','Conventional chemical viticulture for maximum yield','Carbonic maceration for all Loire whites'], answer:1, explanation:'Nicolas Joly (Domaine de la Coulée de Serrant) converted his Savennières estate to biodynamic viticulture in the 1980s and has been its most vocal international advocate. He follows the principles of Rudolf Steiner, using preparations based on cosmic rhythms and treating the vineyard as a living organism.' },
  // ── MORE LANGUEDOC ────────────────────────────────────────
  { id:'fr-lr-009', country:'France', region:'Languedoc-Roussillon', topic:'Appellations', difficulty:'Medium', question:'Which Languedoc sub-appellation (within AOP Languedoc) sits on limestone plateau at elevation near Montpellier and is known for fresh, garrigue-scented reds?', options:['Pic Saint-Loup','Terrasses du Larzac','La Clape','Pézenas'], answer:0, explanation:'Pic Saint-Loup AOC is a sub-appellation of AOP Languedoc on a high plateau north of Montpellier, dominated by Syrah and Grenache. The iconic Pic Saint-Loup mountain shelters the vineyards. Cool nights due to elevation give the wines freshness unusual for the Languedoc.' },
  { id:'fr-lr-010', country:'France', region:'Languedoc-Roussillon', topic:'Styles', difficulty:'Medium', question:'Maury AOC in Roussillon produces a Vin Doux Naturel from which grape variety, and what are its two main styles?', options:['Muscat Blanc, fresh-young or aged-rancio','Grenache Noir, fresh (grenat) and aged/oxidative (tuilé, ambré, rancio)','Carignan, always young and unoaked','Mourvèdre, only in aged oxidative style'], answer:1, explanation:'Maury AOC VDN is based on Grenache Noir. There are two main styles: Maury Sec (dry, unfortified Grenache) and Maury VDN — within VDN, wines can be grenat (young, fruity, fresh, no oxidation) or tuilé/ambré/rancio (aged oxidatively with characteristic dried fruit, nut, chocolate complexity).' },
  { id:'fr-lr-011', country:'France', region:'Languedoc-Roussillon', topic:'Business', difficulty:'Medium', question:'The Languedoc-Roussillon is France\'s largest wine region by volume. What proportion of all French wine does it produce?', options:['About 5%','Around 10%','Approximately one-third','About two-thirds'], answer:2, explanation:'The Languedoc-Roussillon produces approximately one-third of all French wine by volume, making it France\'s largest wine region. It spans four departments: Gard, Hérault, Aude, and Pyrénées-Orientales. Much production is IGP Pays d\'Oc for export markets.' },
  { id:'fr-lr-012', country:'France', region:'Languedoc-Roussillon', topic:'Grape Varieties', difficulty:'Medium', question:'Which white Languedoc variety, grown primarily around the Bassin de Thau lagoon, is known for high acidity and is used for Picpoul de Pinet AOC?', options:['Grenache Blanc','Marsanne','Piquepoul Blanc (Picpoul Blanc)','Roussanne'], answer:2, explanation:'Piquepoul Blanc (also spelled Picpoul) is the grape variety used for Picpoul de Pinet AOC. The name means "lip stinger" — a reference to its high natural acidity. It produces crisp, refreshing whites ideal with local oysters and seafood.' },
  // ── MORE BEAUJOLAIS ───────────────────────────────────────
  { id:'fr-bj-006', country:'France', region:'Beaujolais', topic:'Appellations', difficulty:'Medium', question:'Which Beaujolais Cru is considered the most powerful, structured, and age-worthy, often compared to fine Burgundy in complexity?', options:['Fleurie','Chiroubles','Moulin-à-Vent','Saint-Amour'], answer:2, explanation:'Moulin-à-Vent (named after a famous windmill) is widely regarded as Beaujolais\' most serious Cru, producing structured, age-worthy wines that can develop for 10–15+ years. The manganese-rich granite soils are thought to contribute to its unusual longevity for a Gamay wine.' },
  { id:'fr-bj-007', country:'France', region:'Beaujolais', topic:'Appellations', difficulty:'Medium', question:'Fleurie is often called the "queen of Beaujolais Crus." What is its typical character?', options:['Very tannic, dark, and brooding — the most structured Cru','Light, floral, and silky — among the most delicate Beaujolais Crus with violet and rose aromas','Very sweet and low in alcohol, designed for early drinking','The most alcoholic and rich of the Crus, with dark fruit'], answer:1, explanation:'Fleurie (meaning "flowering") is known for delicate, floral, silky wines with violet, rose, and red fruit aromas. Its granite soils produce wines that are elegantly perfumed — considered by many the most feminine Beaujolais Cru, in contrast to the more powerful Moulin-à-Vent or Morgon.' },
  { id:'fr-bj-008', country:'France', region:'Beaujolais', topic:'Wine Law', difficulty:'Easy', question:'Beaujolais Nouveau must not be sold before which date each year?', options:['October 1st','The first Wednesday of November','The third Thursday of November','December 1st'], answer:2, explanation:'Beaujolais Nouveau is released simultaneously worldwide on the third Thursday of November. This creates a global marketing event. The wine is made from the current harvest (typically late September/October) so it reaches market just 6–8 weeks after picking.' },
  { id:'fr-bj-009', country:'France', region:'Beaujolais', topic:'Grape Growing', difficulty:'Medium', question:'What viticultural practice is traditional in the Beaujolais Crus, where each vine is trained as a small individual bush without wires or support?', options:['Double Guyot on trellis','Gobelet (en gobelet / goblet training)','Lenz Moser high culture','Pergola'], answer:1, explanation:'Gobelet (bush vine training) is traditional in Beaujolais, where each vine is pruned back to several short spurs forming a low bush shape. No trellis wires are used. The method requires 100% manual harvesting (no machines), which is compulsory for the Beaujolais Crus.' },
  { id:'fr-bj-010', country:'France', region:'Beaujolais', topic:'Appellations', difficulty:'Hard', question:'Which Beaujolais Cru is located on the slopes of an extinct volcano (Côte de Brouilly) and sits within the larger Brouilly AOC?', options:['Moulin-à-Vent','Régnié','Côte de Brouilly','Morgon'], answer:2, explanation:'Côte de Brouilly is a separate, smaller Cru appellation on the volcanic slopes of Mont Brouilly within the larger Brouilly AOC area. The blue diorite volcanic soils give wines with mineral concentration and more power than surrounding Brouilly.' },
  // ── MORE ALSACE ───────────────────────────────────────────
  { id:'fr-al-011', country:'France', region:'Alsace', topic:'Appellations', difficulty:'Medium', question:'What is the Route des Vins d\'Alsace, and how long is it?', options:['A classified wine route covering only Grand Cru vineyards, 30km long','A tourist wine route running approximately 170km along the eastern foothills of the Vosges, from Thann in the south to Marlenheim in the north','A 50km cycling path between Strasbourg and Colmar','A water route along the Rhine connecting Alsace wine villages'], answer:1, explanation:'The Route des Vins d\'Alsace (Alsace Wine Route) is a famous 170km tourist route along the eastern foothills of the Vosges Mountains, linking wine villages from Marlenheim (north) to Thann (south). It was established in 1953 and passes through many picturesque medieval towns and Grand Cru vineyards.' },
  { id:'fr-al-012', country:'France', region:'Alsace', topic:'Winemaking', difficulty:'Medium', question:'What is the tall, narrow Alsace bottle shape (called "flûte d\'Alsace") required for all AOC Alsace wines?', options:['A standard Bordeaux-shaped bottle with high shoulders','A tall, narrow, elongated bottle similar to those used in the Mosel and Rhineland — the flûte','A squat, flask-shaped bottle like those from Franken','A standard Burgundy-style bottle'], answer:1, explanation:'Alsace AOC wines must be bottled in the tall, narrow "flûte d\'Alsace" — similar in shape to German Mosel bottles. This bottle shape is legally required for all AOC Alsace wines (except Crémant d\'Alsace, which uses a Champagne-style bottle).' },
  { id:'fr-al-013', country:'France', region:'Alsace', topic:'History', difficulty:'Hard', question:'Alsace\'s history of alternating French and German political control has significantly shaped its wine culture. In which year did Alsace become definitively French (after the Second World War)?', options:['1870','1918','1945','1958'], answer:2, explanation:'Alsace has alternated between French and German control: French until 1871 (Franco-Prussian War), then German until 1918, French from 1918, German-occupied 1940–44, and definitively French from 1945. This explains the region\'s unique dual cultural identity — German-style grape labelling on French wines.' },
  { id:'fr-al-014', country:'France', region:'Alsace', topic:'Business', difficulty:'Medium', question:'Which type of producer structure dominates Alsace wine production and marketing?', options:['Small single-domain estates with only their own Grand Cru production','Négociant houses (such as Hugel, Trimbach, Beyer, Zind-Humbrecht) who buy grapes and produce large quantities, alongside grower estates','Large cooperative producers who control 90% of production','The French government controls all Alsace production through INAO'], answer:1, explanation:'Alsace wine production is dominated by a mix of large négociant houses (Hugel & Fils, F.E. Trimbach, Léon Beyer, Domaines Schlumberger) who buy grapes from growers and produce large volumes, and individual grower estates. Cooperatives are also important. The négociants built Alsace\'s international reputation.' },
  // ── MORE SOUTH-WEST ──────────────────────────────────────
  { id:'fr-sw-005', country:'France', region:'South-West France', topic:'Appellations', difficulty:'Medium', question:'Bergerac AOC, in the Périgord, is often described as a less expensive alternative to which great Bordeaux appellation?', options:['Pomerol','Saint-Émilion','Sauternes (for sweet Monbazillac)','Pauillac'], answer:1, explanation:'Bergerac DOC shares the same grape varieties as Bordeaux (Merlot, Cabernet Sauvignon, Cabernet Franc, and for whites: Sauvignon Blanc, Sémillon) and is often compared to Saint-Émilion (for reds). Monbazillac, within the broader Bergerac area, produces Sauternes-style sweet wines from botrytised Sémillon.' },
  { id:'fr-sw-006', country:'France', region:'South-West France', topic:'Grape Varieties', difficulty:'Hard', question:'Irouléguy is the most southwestern AOC in France, in the Basque Country. Which grape varieties are used for its reds and whites?', options:['Malbec (Côt) and Tannat for reds; Gros Manseng for whites','Tannat and Cabernet Franc for reds; Gros Manseng and Petit Courbu for whites','Négrette for reds; Sauvignon Blanc for whites','Cabernet Sauvignon only for reds; no white wine produced'], answer:1, explanation:'Irouléguy AOC (Pyrénées-Atlantiques, in the Pays Basque) produces red and rosé wines primarily from Tannat and Cabernet Franc, and whites from Gros Manseng and Petit Courbu (with some Petit Manseng). The vineyards are on steep, terraced slopes at altitude.' },
  // ── FINAL BORDEAUX BATCH ─────────────────────────────────
  { id:'fr-bx-046', country:'France', region:'Bordeaux', topic:'Climate', difficulty:'Hard', question:'What is a "millésime exceptionnel" (exceptional vintage) in Bordeaux terms, and what weather conditions typically characterise it?', options:['A year with high rainfall throughout the growing season allowing maximum yields','A year with a warm, dry summer and autumn, allowing full phenolic and sugar ripeness without rot — producing deeply coloured, concentrated, structured wines','A year defined exclusively by the number of Parker points awarded','A year where frost destroys half the crop, concentrating the remaining berries'], answer:1, explanation:'Exceptional Bordeaux vintages (e.g. 2009, 2010, 2016, 2020) are typically characterised by warm, sunny summers with moderate rainfall at key growth stages, followed by dry, warm autumns allowing Cabernet Sauvignon to ripen fully without rot. Low yields from small berries concentrated flavours. These vintages command significant price premiums.' },
  { id:'fr-bx-047', country:'France', region:'Bordeaux', topic:'Soils', difficulty:'Medium', question:'What is "crasse de fer" soil and in which Bordeaux appellation is it most famously found?', options:['An iron-rich clay and ferrous oxide soil unique to Pomerol, associated with Pétrus\'s unique blue clay plateau','A calcium-rich limestone soil in Saint-Émilion','The gravel deposits beneath the Médoc','A sandy soil type found in Entre-Deux-Mers'], answer:0, explanation:'Crasse de fer (iron-enriched clay) is found on the famous plateau of Pomerol, most notably under Pétrus (which sits on a unique blue clay pocket with high iron oxide). The clay retains moisture, the iron drains excess water, and the combination suits Merlot exceptionally well.' },
  { id:'fr-bx-048', country:'France', region:'Bordeaux', topic:'Appellations', difficulty:'Medium', question:'Which large Bordeaux appellation sits between the Garonne and Dordogne rivers, primarily producing dry white wines?', options:['Blaye Côtes de Bordeaux','Côtes de Bourg','Entre-Deux-Mers','Lalande de Pomerol'], answer:2, explanation:'Entre-Deux-Mers ("between two seas") is the large triangular zone between the Garonne and Dordogne rivers. The appellation produces predominantly dry white wine (Sauvignon Blanc, Sémillon, Muscadelle). Red wines from the same area are sold as Bordeaux or Bordeaux Supérieur AOC.' },
  { id:'fr-bx-049', country:'France', region:'Bordeaux', topic:'Wine Law', difficulty:'Medium', question:'What does "Bordeaux Supérieur" indicate compared to basic "Bordeaux AOC"?', options:['It indicates wines classified above Cru Bourgeois in the 1855 hierarchy','It is a higher minimum alcohol level (10.5% vs 10%) and lower maximum yield (45 hl/ha vs 55 hl/ha), typically indicating a slightly higher quality threshold','It means the wine must be aged minimum 24 months before release','It is a designation exclusive to the Right Bank and Pomerol'], answer:1, explanation:'Bordeaux Supérieur AOC requires a slightly lower maximum yield and a higher minimum alcohol than Bordeaux AOC, suggesting slightly more concentrated, riper grapes. In practice, quality among Bordeaux Supérieur wines varies widely, but the appellation indicates a step up from generic Bordeaux.' },
  { id:'fr-bx-050', country:'France', region:'Bordeaux', topic:'Styles', difficulty:'Easy', question:'What is the typical ageing potential of a high-quality Left Bank Bordeaux Premier Cru from a great vintage?', options:['2–5 years maximum','5–10 years','10–25 years minimum; the best can improve for 40–50+ years','Bordeaux wines do not improve with age'], answer:2, explanation:'Top Left Bank Bordeaux Premiers Crus (Lafite, Latour, Margaux, Mouton Rothschild) from great vintages (1990, 2000, 2005, 2009, 2010) typically need 10–20 years to fully open up and can improve for 40–50+ years. The high tannins and acidity in Cabernet Sauvignon-dominant wines provide the structural backbone for long ageing.' },
]

